INSERT INTO cards (id, category, front, back, key_points, data) VALUES
(1, 'DDIA', 'What is the fundamental meta-principle of software architecture?', 'System design is fundamentally about tradeoffs, not best practices.', '["No universally correct solutions — only decisions that fit specific requirements","Tradeoffs are unavoidable: consistency vs. availability, latency vs. throughput, simplicity vs. flexibility","Making tradeoffs explicit separates architecture from accidental complexity"]', '{"id":1,"category":"DDIA","front":"What is the fundamental meta-principle of software architecture?","back":"System design is fundamentally about tradeoffs, not best practices.","keyPoints":["No universally correct solutions — only decisions that fit specific requirements","Tradeoffs are unavoidable: consistency vs. availability, latency vs. throughput, simplicity vs. flexibility","Making tradeoffs explicit separates architecture from accidental complexity"],"exerciseType":"mcq","choices":["Follow industry best practices consistently","System design is fundamentally about tradeoffs","Always choose the most scalable solution","Optimize for performance above all else"],"correctAnswer":1}'),
(2, 'DDIA', 'What are the three foundational concerns of data-intensive applications?', 'Reliability, Scalability, and Maintainability — the three axes for evaluating any data system design.', '["Reliability: works correctly despite faults (fault-tolerant ≠ fault-free)","Scalability: handles growth — not binary, but ''what are our options for coping?''","Maintainability: operability (easy to run), simplicity (easy to understand), evolvability (easy to change)"]', '{"id":2,"category":"DDIA","front":"What are the three foundational concerns of data-intensive applications?","back":"Reliability, Scalability, and Maintainability — the three axes for evaluating any data system design.","keyPoints":["Reliability: works correctly despite faults (fault-tolerant ≠ fault-free)","Scalability: handles growth — not binary, but ''what are our options for coping?''","Maintainability: operability (easy to run), simplicity (easy to understand), evolvability (easy to change)"],"exerciseType":"mcq","choices":["Speed, Security, and Simplicity","Reliability, Scalability, and Maintainability","Consistency, Availability, and Partition tolerance","Latency, Throughput, and Durability"],"correctAnswer":1}'),
(3, 'DDIA', 'What are the two fundamental strategies for distributing data?', 'Replication (copies for fault tolerance) and Partitioning/Sharding (splitting for write scaling).', '["Replication: single-leader, multi-leader, or leaderless — each with different consistency tradeoffs","Partitioning: split data so each machine holds a subset — key selection determines query patterns","Usually combined: each partition is replicated across multiple nodes"]', '{"id":3,"category":"DDIA","front":"What are the two fundamental strategies for distributing data?","back":"Replication (copies for fault tolerance) and Partitioning/Sharding (splitting for write scaling).","keyPoints":["Replication: single-leader, multi-leader, or leaderless — each with different consistency tradeoffs","Partitioning: split data so each machine holds a subset — key selection determines query patterns","Usually combined: each partition is replicated across multiple nodes"],"exerciseType":"fill-blank","correctAnswer":"replication"}'),
(4, 'DDIA', 'Describe the spectrum of consistency models in distributed systems.', 'Consistency ranges from eventual (weakest, cheapest) to linearizable (strongest, most expensive).', '["Eventual: replicas converge eventually, no timing guarantee — fine for feeds, analytics","Causal: respects causal ordering without global coordination","Linearizable: behaves as if one copy of data, all operations atomic — needed for locks, leader election","Choose the weakest model that preserves correctness for each operation"]', '{"id":4,"category":"DDIA","front":"Describe the spectrum of consistency models in distributed systems.","back":"Consistency ranges from eventual (weakest, cheapest) to linearizable (strongest, most expensive).","keyPoints":["Eventual: replicas converge eventually, no timing guarantee — fine for feeds, analytics","Causal: respects causal ordering without global coordination","Linearizable: behaves as if one copy of data, all operations atomic — needed for locks, leader election","Choose the weakest model that preserves correctness for each operation"]}'),
(5, 'DDIA', 'How do transaction isolation levels relate to the correctness-concurrency tradeoff?', 'Stronger isolation prevents more anomalies but costs more performance. The spectrum: Read Committed → Snapshot Isolation → Serializable.', '["Read Committed: prevents dirty reads/writes, not read skew","Snapshot Isolation (MVCC): consistent snapshot per transaction, but misses write skew","Serializable: equivalent to serial execution — via actual serial, 2PL (pessimistic), or SSI (optimistic)","Write skew is the sneaky bug that only serializability prevents"]', '{"id":5,"category":"DDIA","front":"How do transaction isolation levels relate to the correctness-concurrency tradeoff?","back":"Stronger isolation prevents more anomalies but costs more performance. The spectrum: Read Committed → Snapshot Isolation → Serializable.","keyPoints":["Read Committed: prevents dirty reads/writes, not read skew","Snapshot Isolation (MVCC): consistent snapshot per transaction, but misses write skew","Serializable: equivalent to serial execution — via actual serial, 2PL (pessimistic), or SSI (optimistic)","Write skew is the sneaky bug that only serializability prevents"]}'),
(6, 'Distributed Systems', 'What does the CAP theorem actually say?', 'During a network partition, a distributed system must choose between Consistency and Availability. Partitions are inevitable, so the real choice is CP vs. AP.', '["CP: returns errors during partitions rather than stale data (HBase, MongoDB majority reads)","AP: stays available during partitions but may return stale data (Cassandra, DynamoDB)","It''s not ''pick 2 of 3'' — it''s ''during a partition, sacrifice C or A''","CAP says nothing about normal operation — that''s where PACELC matters"]', '{"id":6,"category":"Distributed Systems","front":"What does the CAP theorem actually say?","back":"During a network partition, a distributed system must choose between Consistency and Availability. Partitions are inevitable, so the real choice is CP vs. AP.","keyPoints":["CP: returns errors during partitions rather than stale data (HBase, MongoDB majority reads)","AP: stays available during partitions but may return stale data (Cassandra, DynamoDB)","It''s not ''pick 2 of 3'' — it''s ''during a partition, sacrifice C or A''","CAP says nothing about normal operation — that''s where PACELC matters"],"exerciseType":"mcq","choices":["Pick any 2 of Consistency, Availability, and Partition tolerance","During a partition, choose between Consistency and Availability","You can have all three if you use the right database","Consistency and Availability are always in conflict"],"correctAnswer":1}'),
(7, 'Distributed Systems', 'How does PACELC extend the CAP theorem?', 'PACELC adds: even without partitions (Else), there''s a tradeoff between Latency and Consistency. This matters more day-to-day than CAP.', '["PA/EL (Cassandra): available during partitions, low-latency normally — weak consistency","PC/EC (sync RDBMS): consistent always, pays latency cost","Google Spanner achieves PC/EC via GPS-synchronized TrueTime clocks (~7ms commit wait)","The right question: ''what consistency-latency tradeoff during normal operation?''"]', '{"id":7,"category":"Distributed Systems","front":"How does PACELC extend the CAP theorem?","back":"PACELC adds: even without partitions (Else), there''s a tradeoff between Latency and Consistency. This matters more day-to-day than CAP.","keyPoints":["PA/EL (Cassandra): available during partitions, low-latency normally — weak consistency","PC/EC (sync RDBMS): consistent always, pays latency cost","Google Spanner achieves PC/EC via GPS-synchronized TrueTime clocks (~7ms commit wait)","The right question: ''what consistency-latency tradeoff during normal operation?''"]}'),
(8, 'Distributed Systems', 'What problem do consensus algorithms solve, and how does Raft work?', 'Consensus gets multiple nodes to agree on a value despite failures. Raft decomposes this into leader election + log replication.', '["Raft: leader elected by majority vote after randomized election timeout (150-300ms)","Leader accepts writes, replicates log to followers, commits after majority acknowledgment","A 2f+1 cluster tolerates f failures (5 nodes → 2 can fail)","Used by: etcd, Consul, TiKV, CockroachDB, Kafka metadata"]', '{"id":8,"category":"Distributed Systems","front":"What problem do consensus algorithms solve, and how does Raft work?","back":"Consensus gets multiple nodes to agree on a value despite failures. Raft decomposes this into leader election + log replication.","keyPoints":["Raft: leader elected by majority vote after randomized election timeout (150-300ms)","Leader accepts writes, replicates log to followers, commits after majority acknowledgment","A 2f+1 cluster tolerates f failures (5 nodes → 2 can fail)","Used by: etcd, Consul, TiKV, CockroachDB, Kafka metadata"],"exerciseType":"fill-blank","correctAnswer":"consensus"}'),
(9, 'Architecture', 'What is a bounded context, and why does it matter for microservices?', 'A boundary within which a particular domain model is defined. Bounded contexts are the natural unit of microservice decomposition — split by business domain, not technical layers.', '["The word ''Customer'' can mean different things in billing vs. shipping — and that''s fine","Ubiquitous language: shared vocabulary within a context that maps directly to code","Context mapping defines relationships: shared kernel, anti-corruption layer, etc.","Wrong boundaries → distributed monolith (all the costs, none of the benefits)"]', '{"id":9,"category":"Architecture","front":"What is a bounded context, and why does it matter for microservices?","back":"A boundary within which a particular domain model is defined. Bounded contexts are the natural unit of microservice decomposition — split by business domain, not technical layers.","keyPoints":["The word ''Customer'' can mean different things in billing vs. shipping — and that''s fine","Ubiquitous language: shared vocabulary within a context that maps directly to code","Context mapping defines relationships: shared kernel, anti-corruption layer, etc.","Wrong boundaries → distributed monolith (all the costs, none of the benefits)"]}'),
(10, 'Architecture', 'What is Clean Architecture''s Dependency Rule?', 'Source code dependencies must only point inward — inner circles know nothing about outer circles. Domain logic at center, frameworks at edges.', '["Four layers: Entities → Use Cases → Interface Adapters → Frameworks & Drivers","Ports (interfaces defined by domain) + Adapters (implementations for infrastructure)","Key inversion: the database depends on business logic interfaces, not the reverse","Benefits: framework independence, testability, database flexibility"]', '{"id":10,"category":"Architecture","front":"What is Clean Architecture''s Dependency Rule?","back":"Source code dependencies must only point inward — inner circles know nothing about outer circles. Domain logic at center, frameworks at edges.","keyPoints":["Four layers: Entities → Use Cases → Interface Adapters → Frameworks & Drivers","Ports (interfaces defined by domain) + Adapters (implementations for infrastructure)","Key inversion: the database depends on business logic interfaces, not the reverse","Benefits: framework independence, testability, database flexibility"]}'),
(11, 'Architecture', 'What is a distributed monolith, and why is it the worst outcome?', 'Services that are split into separate deployments but still tightly coupled — all the costs of distributed systems with none of the benefits.', '["Caused by: shared database schemas, synchronous call chains, shared business logic libraries","The test: can you deploy this service without coordinating with any other team?","Fix: each service owns its data, favor async communication, align with bounded contexts","A well-structured monolith is vastly preferable to a distributed monolith"]', '{"id":11,"category":"Architecture","front":"What is a distributed monolith, and why is it the worst outcome?","back":"Services that are split into separate deployments but still tightly coupled — all the costs of distributed systems with none of the benefits.","keyPoints":["Caused by: shared database schemas, synchronous call chains, shared business logic libraries","The test: can you deploy this service without coordinating with any other team?","Fix: each service owns its data, favor async communication, align with bounded contexts","A well-structured monolith is vastly preferable to a distributed monolith"]}'),
(12, 'Architecture', 'What is event sourcing?', 'Store state as a chronological, append-only sequence of events — not mutable rows. Current state is derived by replaying the event log.', '["The event log is the source of truth; current state views are derived projections","Advantages: full audit trail, temporal queries, replay for debugging, flexible projections","Challenges: schema evolution, eventual consistency, unbounded log growth, GDPR conflicts","Best for: financial systems, order management, compliance — overkill for simple CRUD"]', '{"id":12,"category":"Architecture","front":"What is event sourcing?","back":"Store state as a chronological, append-only sequence of events — not mutable rows. Current state is derived by replaying the event log.","keyPoints":["The event log is the source of truth; current state views are derived projections","Advantages: full audit trail, temporal queries, replay for debugging, flexible projections","Challenges: schema evolution, eventual consistency, unbounded log growth, GDPR conflicts","Best for: financial systems, order management, compliance — overkill for simple CRUD"],"exerciseType":"mcq","choices":["Store the latest state snapshot in a mutable database","Store state as a chronological, append-only sequence of events","Cache frequently accessed data in memory","Replicate state across multiple data centers"],"correctAnswer":1}'),
(13, 'Architecture', 'What is CQRS, and when should you use it?', 'Command Query Responsibility Segregation: separate models for reading and writing. Commands enforce business rules; queries are denormalized for performance.', '["Write model: normalized, consistent, enforces rules. Read model: denormalized, eventually consistent, fast","Natural pairing with event sourcing: commands → events → read projections","Enables independent scaling of reads vs. writes","Only worth the complexity when read/write patterns diverge significantly"]', '{"id":13,"category":"Architecture","front":"What is CQRS, and when should you use it?","back":"Command Query Responsibility Segregation: separate models for reading and writing. Commands enforce business rules; queries are denormalized for performance.","keyPoints":["Write model: normalized, consistent, enforces rules. Read model: denormalized, eventually consistent, fast","Natural pairing with event sourcing: commands → events → read projections","Enables independent scaling of reads vs. writes","Only worth the complexity when read/write patterns diverge significantly"]}'),
(14, 'Architecture', 'Compare Lambda and Kappa data processing architectures.', 'Lambda runs batch + stream in parallel (accurate but complex). Kappa treats everything as streams (simpler, one codebase). Kappa is winning in 2026.', '["Lambda: batch layer (accuracy) + speed layer (immediacy) + serving layer (merged view)","Lambda''s problem: two codebases that must produce identical results","Kappa: immutable event log as source of truth, reprocess by replaying with new code","2026 trend: Kappa + lakehouse hybrids for analytics and ML"]', '{"id":14,"category":"Architecture","front":"Compare Lambda and Kappa data processing architectures.","back":"Lambda runs batch + stream in parallel (accurate but complex). Kappa treats everything as streams (simpler, one codebase). Kappa is winning in 2026.","keyPoints":["Lambda: batch layer (accuracy) + speed layer (immediacy) + serving layer (merged view)","Lambda''s problem: two codebases that must produce identical results","Kappa: immutable event log as source of truth, reprocess by replaying with new code","2026 trend: Kappa + lakehouse hybrids for analytics and ML"]}'),
(15, 'Infrastructure', 'What are the three fundamental infrastructure primitives for scaling?', 'Load balancers, caches, and CDNs. These solve most scaling problems before you need exotic distributed systems.', '["Load balancers: L4 (transport) vs. L7 (application) — distribute requests, health-check backends","Caches: Redis/Memcached between app and DB — the single most impactful read optimization","CDNs: geographically distributed cache, often handles 80%+ of requests","They compose: CDN → LB → app → cache → DB. Each layer absorbs load for the next"]', '{"id":15,"category":"Infrastructure","front":"What are the three fundamental infrastructure primitives for scaling?","back":"Load balancers, caches, and CDNs. These solve most scaling problems before you need exotic distributed systems.","keyPoints":["Load balancers: L4 (transport) vs. L7 (application) — distribute requests, health-check backends","Caches: Redis/Memcached between app and DB — the single most impactful read optimization","CDNs: geographically distributed cache, often handles 80%+ of requests","They compose: CDN → LB → app → cache → DB. Each layer absorbs load for the next"]}'),
(16, 'Infrastructure', 'How do Postgres, Cassandra, DynamoDB, and Redis embody different architecture tradeoffs?', 'Each database makes specific consistency/latency/scale choices. Often used together, each handling the workload it''s suited for.', '["Postgres: strong consistency, ACID, rich queries — the default unless you have a reason not to","Cassandra: AP/tunable, masterless, LSM trees — write-heavy at massive scale (IoT, time-series)","DynamoDB: managed, auto-scaling, single-digit-ms — serverless, simple access patterns","Redis: sub-ms in-memory — caching, sessions, leaderboards, rate limiting (not primary storage)"]', '{"id":16,"category":"Infrastructure","front":"How do Postgres, Cassandra, DynamoDB, and Redis embody different architecture tradeoffs?","back":"Each database makes specific consistency/latency/scale choices. Often used together, each handling the workload it''s suited for.","keyPoints":["Postgres: strong consistency, ACID, rich queries — the default unless you have a reason not to","Cassandra: AP/tunable, masterless, LSM trees — write-heavy at massive scale (IoT, time-series)","DynamoDB: managed, auto-scaling, single-digit-ms — serverless, simple access patterns","Redis: sub-ms in-memory — caching, sessions, leaderboards, rate limiting (not primary storage)"]}'),
(17, 'SRE', 'What should SLIs measure, and how do SLIs/SLOs/SLAs relate?', 'SLIs should measure user experience, not internal metrics. SLI (what you measure) → SLO (your target) → SLA (contractual commitment).', '["Good SLIs: request latency, error rate, availability as perceived by clients","Anti-pattern: CPU/memory as proxy for user happiness — a server at 90% CPU may be fine","SLOs set based on what users need, not what the system can achieve","Multi-window, multi-burn-rate alerting is best practice"]', '{"id":17,"category":"SRE","front":"What should SLIs measure, and how do SLIs/SLOs/SLAs relate?","back":"SLIs should measure user experience, not internal metrics. SLI (what you measure) → SLO (your target) → SLA (contractual commitment).","keyPoints":["Good SLIs: request latency, error rate, availability as perceived by clients","Anti-pattern: CPU/memory as proxy for user happiness — a server at 90% CPU may be fine","SLOs set based on what users need, not what the system can achieve","Multi-window, multi-burn-rate alerting is best practice"]}'),
(18, 'SRE', 'How do error budgets work, and why are they SRE''s key innovation?', 'Error budget = 100% minus the SLO. It''s a quantitative resource: spent = ship fast, exhausted = freeze and fix reliability. Makes reliability negotiable.', '["99.9% SLO → 0.1% error budget → ~43 min downtime/month","Budget exhausted → freeze non-critical releases until recovery","Unused budget means the team could be shipping faster","Aligns incentives: product teams and ops teams share the same number"]', '{"id":18,"category":"SRE","front":"How do error budgets work, and why are they SRE''s key innovation?","back":"Error budget = 100% minus the SLO. It''s a quantitative resource: spent = ship fast, exhausted = freeze and fix reliability. Makes reliability negotiable.","keyPoints":["99.9% SLO → 0.1% error budget → ~43 min downtime/month","Budget exhausted → freeze non-critical releases until recovery","Unused budget means the team could be shipping faster","Aligns incentives: product teams and ops teams share the same number"],"exerciseType":"fill-blank","correctAnswer":"error budget"}'),
(19, 'SRE', 'What is ''toil'' in SRE, and why does it matter?', 'Toil is operational work that is manual, repetitive, automatable, tactical, devoid of enduring value, and scales linearly with service size.', '["The test: if the work doubles when the service doubles, it''s toil","Google target: SREs spend ≤50% on toil, ≥50% on engineering to reduce future toil","Toil crowds out engineering work — creates a death spiral if unchecked","Not all ops work is toil: on-call (strategic), postmortems (learning) are not toil"]', '{"id":19,"category":"SRE","front":"What is ''toil'' in SRE, and why does it matter?","back":"Toil is operational work that is manual, repetitive, automatable, tactical, devoid of enduring value, and scales linearly with service size.","keyPoints":["The test: if the work doubles when the service doubles, it''s toil","Google target: SREs spend ≤50% on toil, ≥50% on engineering to reduce future toil","Toil crowds out engineering work — creates a death spiral if unchecked","Not all ops work is toil: on-call (strategic), postmortems (learning) are not toil"]}'),
(20, 'SRE', 'Why does Google SRE treat incident management as a practiced discipline?', 'Structured roles (IC, Ops Lead, Comms Lead), runbooks, and communication cadence beat heroic ad-hoc firefighting. Design the process before the incident.', '["Incident Commander coordinates — doesn''t debug. Delegates technical work","Severity levels pre-defined by user/revenue/data impact — no debate during incidents","Runbooks: tested procedures for known failure modes. 3am on-call shouldn''t be inventing","Complete loop: SLIs detect → error budgets quantify → incidents resolve → postmortems prevent"]', '{"id":20,"category":"SRE","front":"Why does Google SRE treat incident management as a practiced discipline?","back":"Structured roles (IC, Ops Lead, Comms Lead), runbooks, and communication cadence beat heroic ad-hoc firefighting. Design the process before the incident.","keyPoints":["Incident Commander coordinates — doesn''t debug. Delegates technical work","Severity levels pre-defined by user/revenue/data impact — no debate during incidents","Runbooks: tested procedures for known failure modes. 3am on-call shouldn''t be inventing","Complete loop: SLIs detect → error budgets quantify → incidents resolve → postmortems prevent"]}'),
(21, 'SRE', 'What makes a postmortem ''blameless,'' and why does it matter?', 'Blameless postmortems assume everyone acted in good faith with available information. Focus on fixing the system, not punishing individuals. Blame drives hiding; learning drives improvement.', '["Trigger ≠ root cause: a deploy may trigger an outage, but the root cause is missing canary analysis","Required: impact summary, timeline, root causes, action items with owners and deadlines","Originated in healthcare/aviation where blame culture is literally fatal","Organizational benefit: faster incident reporting, more honest sharing, actual learning"]', '{"id":21,"category":"SRE","front":"What makes a postmortem ''blameless,'' and why does it matter?","back":"Blameless postmortems assume everyone acted in good faith with available information. Focus on fixing the system, not punishing individuals. Blame drives hiding; learning drives improvement.","keyPoints":["Trigger ≠ root cause: a deploy may trigger an outage, but the root cause is missing canary analysis","Required: impact summary, timeline, root causes, action items with owners and deadlines","Originated in healthcare/aviation where blame culture is literally fatal","Organizational benefit: faster incident reporting, more honest sharing, actual learning"]}'),
(22, 'Learning Science', 'What are the two highest-utility learning techniques according to the Dunlosky meta-analysis?', 'Spaced repetition (d=0.56) and active recall / practice testing (d=0.56). Both rated ''high utility'' across 242 studies and 169k participants.', '["Spaced repetition: distributing reviews over increasing intervals fights the forgetting curve","Active recall: retrieving information from memory strengthens the memory trace more than re-reading","Both are high utility because they generalize across ages, materials, and testing formats","Combined in flashcard apps like Anki: each review is both a recall event and a spacing event"]', '{"id":22,"category":"Learning Science","front":"What are the two highest-utility learning techniques according to the Dunlosky meta-analysis?","back":"Spaced repetition (d=0.56) and active recall / practice testing (d=0.56). Both rated ''high utility'' across 242 studies and 169k participants.","keyPoints":["Spaced repetition: distributing reviews over increasing intervals fights the forgetting curve","Active recall: retrieving information from memory strengthens the memory trace more than re-reading","Both are high utility because they generalize across ages, materials, and testing formats","Combined in flashcard apps like Anki: each review is both a recall event and a spacing event"],"exerciseType":"mcq","choices":["Highlighting and re-reading","Spaced repetition and active recall","Summarization and note-taking","Imagery and keyword mnemonics"],"correctAnswer":1}'),
(23, 'Learning Science', 'What are ''desirable difficulties'' in Bjork''s learning framework?', 'Conditions that make learning harder in the short term but lead to better long-term retention and transfer. The difficulty must be desirable — it should induce productive cognitive effort, not confusion.', '["Key desirable difficulties: spacing, interleaving, generation, and varying practice conditions","The generation effect: producing an answer from memory beats passively recognizing it","Interleaving: mixing different problem types during practice improves discrimination (+43% transfer)","Undesirable difficulty: tasks that are hard because they are unclear or poorly designed provide no benefit"]', '{"id":23,"category":"Learning Science","front":"What are ''desirable difficulties'' in Bjork''s learning framework?","back":"Conditions that make learning harder in the short term but lead to better long-term retention and transfer. The difficulty must be desirable — it should induce productive cognitive effort, not confusion.","keyPoints":["Key desirable difficulties: spacing, interleaving, generation, and varying practice conditions","The generation effect: producing an answer from memory beats passively recognizing it","Interleaving: mixing different problem types during practice improves discrimination (+43% transfer)","Undesirable difficulty: tasks that are hard because they are unclear or poorly designed provide no benefit"]}'),
(24, 'Learning Science', 'Why does interleaving practice improve learning, and by how much?', 'Interleaving — mixing different categories or problem types during study — improves transfer by ~43% compared to blocked practice. It forces the learner to discriminate between concepts, not just repeat a single strategy.', '["Blocked practice feels easier and gives an illusion of mastery, but interleaving produces deeper learning","The discrimination hypothesis: interleaving forces you to identify which strategy applies, not just execute it","Effective in math, music, art identification, medical diagnosis, and flashcard study","Implementation: shuffle cards across categories in chunks rather than studying one topic at a time"]', '{"id":24,"category":"Learning Science","front":"Why does interleaving practice improve learning, and by how much?","back":"Interleaving — mixing different categories or problem types during study — improves transfer by ~43% compared to blocked practice. It forces the learner to discriminate between concepts, not just repeat a single strategy.","keyPoints":["Blocked practice feels easier and gives an illusion of mastery, but interleaving produces deeper learning","The discrimination hypothesis: interleaving forces you to identify which strategy applies, not just execute it","Effective in math, music, art identification, medical diagnosis, and flashcard study","Implementation: shuffle cards across categories in chunks rather than studying one topic at a time"]}'),
(25, 'Learning Science', 'What is the ''illusion of competence'' and how does confidence calibration combat it?', 'Students systematically overestimate how well they know material — re-reading feels fluent but does not create durable memory. Confidence calibration (predicting performance before testing) trains metacognition and exposes the gap.', '["Fluency trap: re-reading highlights feels productive but produces minimal long-term retention","Metacognition — knowing what you don''t know — is a trainable skill and a key predictor of learning success","Calibration exercise: rate confidence before flipping a card, then compare to actual recall quality","Over time, well-calibrated learners allocate study time more efficiently to weak areas"]', '{"id":25,"category":"Learning Science","front":"What is the ''illusion of competence'' and how does confidence calibration combat it?","back":"Students systematically overestimate how well they know material — re-reading feels fluent but does not create durable memory. Confidence calibration (predicting performance before testing) trains metacognition and exposes the gap.","keyPoints":["Fluency trap: re-reading highlights feels productive but produces minimal long-term retention","Metacognition — knowing what you don''t know — is a trainable skill and a key predictor of learning success","Calibration exercise: rate confidence before flipping a card, then compare to actual recall quality","Over time, well-calibrated learners allocate study time more efficiently to weak areas"]}'),
(26, 'Learning Science', 'Why is immediate feedback a strong moderator of learning effectiveness?', 'Feedback closes the gap between what you think you know and what you actually know. Immediate, elaborated feedback (explaining why the answer is correct) is more effective than delayed or simple correct/incorrect signals.', '["Feedback is the strongest moderator in the Dunlosky meta-analysis — it amplifies every other technique","Elaborated feedback (showing the correct answer with explanation) outperforms simple right/wrong signals","In flashcard apps: showing the answer alongside your self-generated response lets you self-correct in real time","Without feedback, practice testing can reinforce errors rather than correct them"]', '{"id":26,"category":"Learning Science","front":"Why is immediate feedback a strong moderator of learning effectiveness?","back":"Feedback closes the gap between what you think you know and what you actually know. Immediate, elaborated feedback (explaining why the answer is correct) is more effective than delayed or simple correct/incorrect signals.","keyPoints":["Feedback is the strongest moderator in the Dunlosky meta-analysis — it amplifies every other technique","Elaborated feedback (showing the correct answer with explanation) outperforms simple right/wrong signals","In flashcard apps: showing the answer alongside your self-generated response lets you self-correct in real time","Without feedback, practice testing can reinforce errors rather than correct them"]}'),
(27, 'Learning Science', 'What makes Duolingo''s gamification model so effective at sustaining engagement?', 'Duolingo combines streaks, XP, leagues, and loss aversion into a habit loop. Users with 7-day streaks are 3.6x more likely to stay engaged, and streaks increase commitment by 60%.', '["Streak mechanism: daily consistency is more valuable than session length — streaks make skipping painful","Streak freezes and recovery options prevent catastrophic motivation loss from a single missed day","Leaderboards and leagues add social competition without requiring friends on the platform","Microlearning sessions (under 10 min) hit 89% completion rate — low barrier drives high consistency"]', '{"id":27,"category":"Learning Science","front":"What makes Duolingo''s gamification model so effective at sustaining engagement?","back":"Duolingo combines streaks, XP, leagues, and loss aversion into a habit loop. Users with 7-day streaks are 3.6x more likely to stay engaged, and streaks increase commitment by 60%.","keyPoints":["Streak mechanism: daily consistency is more valuable than session length — streaks make skipping painful","Streak freezes and recovery options prevent catastrophic motivation loss from a single missed day","Leaderboards and leagues add social competition without requiring friends on the platform","Microlearning sessions (under 10 min) hit 89% completion rate — low barrier drives high consistency"]}'),
(28, 'Learning Science', 'How does FSRS improve on the classic SM-2 spaced repetition algorithm?', 'FSRS (Free Spaced Repetition Scheduler) uses a machine-learned model that outperforms SM-2 in 91.9% of cases, requiring 20-30% fewer reviews to achieve the same retention rate.', '["SM-2 uses a fixed ease factor that degrades over time — FSRS models memory stability and difficulty separately","FSRS parameters: stability (memory strength in days), difficulty (1-10), and target retention (default 0.9)","FSRS adapts to each learner''s actual review history rather than applying the same formula to everyone","Practical impact: fewer reviews means less time spent for the same learning outcome — reduces burnout"]', '{"id":28,"category":"Learning Science","front":"How does FSRS improve on the classic SM-2 spaced repetition algorithm?","back":"FSRS (Free Spaced Repetition Scheduler) uses a machine-learned model that outperforms SM-2 in 91.9% of cases, requiring 20-30% fewer reviews to achieve the same retention rate.","keyPoints":["SM-2 uses a fixed ease factor that degrades over time — FSRS models memory stability and difficulty separately","FSRS parameters: stability (memory strength in days), difficulty (1-10), and target retention (default 0.9)","FSRS adapts to each learner''s actual review history rather than applying the same formula to everyone","Practical impact: fewer reviews means less time spent for the same learning outcome — reduces burnout"]}'),
(29, 'Learning Science', 'What is the microlearning effect, and what session lengths maximize retention?', 'Microlearning — breaking content into sessions under 10 minutes — increases retention by 25-60% and achieves 80%+ completion rates. Short sessions lower the barrier to starting and fit into daily routines.', '["Modules under 10 minutes hit 89% completion vs. much lower rates for longer sessions","Retention boost of 25-60% compared to massed (long-session) study of the same material","The key mechanism: short sessions reduce cognitive overload and encourage daily consistency over cramming","Effective platforms (Duolingo, Anki) default to small daily goals — 5 minutes or 10 cards"]', '{"id":29,"category":"Learning Science","front":"What is the microlearning effect, and what session lengths maximize retention?","back":"Microlearning — breaking content into sessions under 10 minutes — increases retention by 25-60% and achieves 80%+ completion rates. Short sessions lower the barrier to starting and fit into daily routines.","keyPoints":["Modules under 10 minutes hit 89% completion vs. much lower rates for longer sessions","Retention boost of 25-60% compared to massed (long-session) study of the same material","The key mechanism: short sessions reduce cognitive overload and encourage daily consistency over cramming","Effective platforms (Duolingo, Anki) default to small daily goals — 5 minutes or 10 cards"]}'),
(30, 'Learning Science', 'What is the generation effect and how does elaborative interrogation leverage it?', 'The generation effect: producing information from memory creates stronger traces than passively receiving it. Elaborative interrogation extends this by asking ''Why is this true?'' — forcing the learner to connect new facts to existing knowledge.', '["Generation: writing your own answer before seeing the correct one deepens encoding even if the answer is wrong","Elaborative interrogation rated moderate utility in Dunlosky — asking ''why?'' triggers causal reasoning","Creating your own flashcards is itself a generation act — the card author learns more than the card user","Cloze deletion (fill-in-the-blank) cards exploit generation by requiring production from partial cues"]', '{"id":30,"category":"Learning Science","front":"What is the generation effect and how does elaborative interrogation leverage it?","back":"The generation effect: producing information from memory creates stronger traces than passively receiving it. Elaborative interrogation extends this by asking ''Why is this true?'' — forcing the learner to connect new facts to existing knowledge.","keyPoints":["Generation: writing your own answer before seeing the correct one deepens encoding even if the answer is wrong","Elaborative interrogation rated moderate utility in Dunlosky — asking ''why?'' triggers causal reasoning","Creating your own flashcards is itself a generation act — the card author learns more than the card user","Cloze deletion (fill-in-the-blank) cards exploit generation by requiring production from partial cues"]}'),
(31, 'Learning Science', 'What is the meta-lesson of active vs. passive learning, and how should you choose a learning platform?', 'Active learning (recall, generation, problem-solving) consistently outperforms passive learning (watching, reading, highlighting). The best platform is the one that forces you to actively produce, not just consume.', '["Anki/flashcards: best for memorizing factual knowledge (languages, medical terms, definitions) via spaced active recall","Brilliant.org: best for building quantitative intuition (math, physics, CS) via interactive problem-solving before explanation","Duolingo: best for daily habit formation and language basics via gamified microlearning with immediate feedback","The common thread: all effective platforms make you do something — type, solve, recall — before showing the answer"]', '{"id":31,"category":"Learning Science","front":"What is the meta-lesson of active vs. passive learning, and how should you choose a learning platform?","back":"Active learning (recall, generation, problem-solving) consistently outperforms passive learning (watching, reading, highlighting). The best platform is the one that forces you to actively produce, not just consume.","keyPoints":["Anki/flashcards: best for memorizing factual knowledge (languages, medical terms, definitions) via spaced active recall","Brilliant.org: best for building quantitative intuition (math, physics, CS) via interactive problem-solving before explanation","Duolingo: best for daily habit formation and language basics via gamified microlearning with immediate feedback","The common thread: all effective platforms make you do something — type, solve, recall — before showing the answer"]}'),
(32, 'Quant', 'What does the Black-Scholes model price, and what are its key assumptions?', 'Black-Scholes prices European options by modeling the underlying as geometric Brownian motion. It assumes constant volatility, no dividends, continuous trading, and no arbitrage.', '["\\(C = S \\cdot N(d_1) - K e^{-rT} N(d_2)\\) where \\(d_1 = \\frac{\\ln(S/K) + (r + \\sigma^2/2)T}{\\sigma\\sqrt{T}}\\)","Key insight: you can perfectly hedge an option by delta-hedging the underlying — the option price is the cost of this hedge","Constant volatility assumption is the weakest — real markets show volatility smile/skew","Won Scholes and Merton the 1997 Nobel; still the lingua franca of options pricing despite limitations"]', '{"id":32,"category":"Quant","front":"What does the Black-Scholes model price, and what are its key assumptions?","back":"Black-Scholes prices European options by modeling the underlying as geometric Brownian motion. It assumes constant volatility, no dividends, continuous trading, and no arbitrage.","keyPoints":["\\(C = S \\cdot N(d_1) - K e^{-rT} N(d_2)\\) where \\(d_1 = \\frac{\\ln(S/K) + (r + \\sigma^2/2)T}{\\sigma\\sqrt{T}}\\)","Key insight: you can perfectly hedge an option by delta-hedging the underlying — the option price is the cost of this hedge","Constant volatility assumption is the weakest — real markets show volatility smile/skew","Won Scholes and Merton the 1997 Nobel; still the lingua franca of options pricing despite limitations"],"exerciseType":"mcq","choices":["Constant volatility, no dividends, continuous trading, no arbitrage","Variable volatility, dividends included, discrete trading, no arbitrage","Constant volatility, dividends included, continuous trading, arbitrage allowed","Stochastic volatility, no dividends, continuous trading, no arbitrage"],"correctAnswer":0}'),
(33, 'Quant', 'What are the four main Greeks, and what does each measure?', 'Delta \(\partial V/\partial S\), Gamma \(\partial^2 V/\partial S^2\), Theta \(\partial V/\partial t\), and Vega \(\partial V/\partial \sigma\). They quantify an option''s sensitivity to underlying price, convexity, time decay, and volatility.', '["Delta: how much the option price moves per $1 move in the underlying (0 to 1 for calls, -1 to 0 for puts)","Gamma: rate of change of delta — highest for ATM options near expiry; measures hedging frequency needed","Theta: time decay — options lose value every day, accelerating near expiry (the ''rent'' of owning options)","Vega: sensitivity to implied vol — a 1% vol increase changes the option price by vega dollars"]', '{"id":33,"category":"Quant","front":"What are the four main Greeks, and what does each measure?","back":"Delta \\(\\partial V/\\partial S\\), Gamma \\(\\partial^2 V/\\partial S^2\\), Theta \\(\\partial V/\\partial t\\), and Vega \\(\\partial V/\\partial \\sigma\\). They quantify an option''s sensitivity to underlying price, convexity, time decay, and volatility.","keyPoints":["Delta: how much the option price moves per $1 move in the underlying (0 to 1 for calls, -1 to 0 for puts)","Gamma: rate of change of delta — highest for ATM options near expiry; measures hedging frequency needed","Theta: time decay — options lose value every day, accelerating near expiry (the ''rent'' of owning options)","Vega: sensitivity to implied vol — a 1% vol increase changes the option price by vega dollars"],"exerciseType":"fill-blank","correctAnswer":"delta"}'),
(34, 'Quant', 'What is risk-neutral pricing and why does it work?', 'In a complete market with no arbitrage, you can price derivatives by assuming all assets grow at the risk-free rate (the ''risk-neutral measure''). The fair price is the discounted expected payoff under this measure.', '["The fundamental theorem of asset pricing: no arbitrage ↔ existence of a risk-neutral measure","You don''t need to know the real-world probability of stock going up — only the replicating portfolio cost matters","Risk-neutral ≠ investors are risk-neutral; it''s a mathematical trick that gives the same price as hedging arguments","Breaks down in incomplete markets (e.g., stochastic vol) where perfect replication is impossible"]', '{"id":34,"category":"Quant","front":"What is risk-neutral pricing and why does it work?","back":"In a complete market with no arbitrage, you can price derivatives by assuming all assets grow at the risk-free rate (the ''risk-neutral measure''). The fair price is the discounted expected payoff under this measure.","keyPoints":["The fundamental theorem of asset pricing: no arbitrage ↔ existence of a risk-neutral measure","You don''t need to know the real-world probability of stock going up — only the replicating portfolio cost matters","Risk-neutral ≠ investors are risk-neutral; it''s a mathematical trick that gives the same price as hedging arguments","Breaks down in incomplete markets (e.g., stochastic vol) where perfect replication is impossible"]}'),
(35, 'Quant', 'What is Itô''s Lemma and why is it central to quantitative finance?', 'Itô''s Lemma is the chain rule for stochastic calculus. For a function f(S,t) where S follows a diffusion, df includes an extra ½σ²S²f″ term that doesn''t exist in ordinary calculus.', '["\\(df = \\left(\\frac{\\partial f}{\\partial t} + \\mu S \\frac{\\partial f}{\\partial S} + \\frac{1}{2}\\sigma^2 S^2 \\frac{\\partial^2 f}{\\partial S^2}\\right)dt + \\sigma S \\frac{\\partial f}{\\partial S}\\,dW\\)","The extra \\(\\frac{1}{2}\\sigma^2 S^2 f''''\\) term arises because \\((dW)^2 = dt\\) — Brownian motion has non-zero quadratic variation","Applying Ito''s Lemma to \\(\\ln(S)\\) derives GBM: \\(S(T) = S(0) \\exp\\left((\\mu - \\sigma^2/2)T + \\sigma W(T)\\right)\\)","Foundation for deriving Black-Scholes PDE, pricing formulas, and stochastic volatility models"]', '{"id":35,"category":"Quant","front":"What is Itô''s Lemma and why is it central to quantitative finance?","back":"Itô''s Lemma is the chain rule for stochastic calculus. For a function f(S,t) where S follows a diffusion, df includes an extra ½σ²S²f″ term that doesn''t exist in ordinary calculus.","keyPoints":["\\(df = \\left(\\frac{\\partial f}{\\partial t} + \\mu S \\frac{\\partial f}{\\partial S} + \\frac{1}{2}\\sigma^2 S^2 \\frac{\\partial^2 f}{\\partial S^2}\\right)dt + \\sigma S \\frac{\\partial f}{\\partial S}\\,dW\\)","The extra \\(\\frac{1}{2}\\sigma^2 S^2 f''''\\) term arises because \\((dW)^2 = dt\\) — Brownian motion has non-zero quadratic variation","Applying Ito''s Lemma to \\(\\ln(S)\\) derives GBM: \\(S(T) = S(0) \\exp\\left((\\mu - \\sigma^2/2)T + \\sigma W(T)\\right)\\)","Foundation for deriving Black-Scholes PDE, pricing formulas, and stochastic volatility models"]}'),
(36, 'Quant', 'What is Value at Risk (VaR) and what are its limitations?', 'VaR estimates the maximum loss over a time horizon at a given confidence level (e.g., ''1-day 99% VaR = $10M'' means 99% of days the loss won''t exceed $10M). It says nothing about how bad losses can be beyond that threshold.', '["Three methods: historical simulation, variance-covariance (parametric), Monte Carlo simulation","Critical flaw: VaR is not subadditive — combining portfolios can increase VaR, violating diversification logic","Expected Shortfall (CVaR) fixes this: it''s the average loss beyond the VaR threshold and is coherent","Basel III requires banks to use Expected Shortfall at 97.5% confidence for market risk capital"]', '{"id":36,"category":"Quant","front":"What is Value at Risk (VaR) and what are its limitations?","back":"VaR estimates the maximum loss over a time horizon at a given confidence level (e.g., ''1-day 99% VaR = $10M'' means 99% of days the loss won''t exceed $10M). It says nothing about how bad losses can be beyond that threshold.","keyPoints":["Three methods: historical simulation, variance-covariance (parametric), Monte Carlo simulation","Critical flaw: VaR is not subadditive — combining portfolios can increase VaR, violating diversification logic","Expected Shortfall (CVaR) fixes this: it''s the average loss beyond the VaR threshold and is coherent","Basel III requires banks to use Expected Shortfall at 97.5% confidence for market risk capital"]}'),
(37, 'Quant', 'What is the Sharpe Ratio and when does it mislead?', '\(Sharpe = \frac{R_p - R_f}{\sigma_p}\) — excess return per unit of total risk. It''s the most used risk-adjusted performance metric, but assumes returns are normally distributed.', '["A Sharpe > 1 is good, > 2 is very good, > 3 is exceptional (and should trigger suspicion of data issues)","Misleading for non-normal returns: a strategy selling deep OTM options has high Sharpe until it blows up","Annualize by multiplying by \\(\\sqrt{252}\\) (daily) or \\(\\sqrt{12}\\) (monthly) — assumes i.i.d. returns, which is often wrong","Alternatives: Sortino ratio (downside deviation only), Calmar ratio (return / max drawdown)"]', '{"id":37,"category":"Quant","front":"What is the Sharpe Ratio and when does it mislead?","back":"\\(Sharpe = \\frac{R_p - R_f}{\\sigma_p}\\) — excess return per unit of total risk. It''s the most used risk-adjusted performance metric, but assumes returns are normally distributed.","keyPoints":["A Sharpe > 1 is good, > 2 is very good, > 3 is exceptional (and should trigger suspicion of data issues)","Misleading for non-normal returns: a strategy selling deep OTM options has high Sharpe until it blows up","Annualize by multiplying by \\(\\sqrt{252}\\) (daily) or \\(\\sqrt{12}\\) (monthly) — assumes i.i.d. returns, which is often wrong","Alternatives: Sortino ratio (downside deviation only), Calmar ratio (return / max drawdown)"]}'),
(38, 'Quant', 'What is mean-variance optimization and why did Markowitz''s insight matter?', 'Markowitz showed that portfolio risk depends on correlations, not just individual asset risks. Mean-variance optimization finds the portfolio weights that maximize return for a given risk level (the efficient frontier).', '["The key insight: diversification is a ''free lunch'' — combining imperfectly correlated assets reduces total risk","Efficient frontier: the set of portfolios with maximum expected return for each level of variance","In practice, highly sensitive to estimated inputs — small changes in expected returns produce wildly different weights","Black-Litterman model fixes this by blending market equilibrium with investor views as a Bayesian prior"]', '{"id":38,"category":"Quant","front":"What is mean-variance optimization and why did Markowitz''s insight matter?","back":"Markowitz showed that portfolio risk depends on correlations, not just individual asset risks. Mean-variance optimization finds the portfolio weights that maximize return for a given risk level (the efficient frontier).","keyPoints":["The key insight: diversification is a ''free lunch'' — combining imperfectly correlated assets reduces total risk","Efficient frontier: the set of portfolios with maximum expected return for each level of variance","In practice, highly sensitive to estimated inputs — small changes in expected returns produce wildly different weights","Black-Litterman model fixes this by blending market equilibrium with investor views as a Bayesian prior"]}'),
(39, 'Quant', 'What is the volatility smile/skew and what does it reveal about Black-Scholes limitations?', 'Implied volatility varies by strike price — OTM puts are priced with higher vol than ATM options (the ''skew''). This contradicts Black-Scholes'' constant-vol assumption and reflects market pricing of tail risk and jumps.', '["Post-1987 crash: markets permanently price downside protection higher — the skew is a crash premium","The smile means the market implicitly uses a fatter-tailed distribution than lognormal for the underlying","Local volatility (Dupire): deterministic vol surface that fits the smile but has unrealistic dynamics","Stochastic volatility (Heston, SABR): vol itself is random — better dynamics but harder to calibrate"]', '{"id":39,"category":"Quant","front":"What is the volatility smile/skew and what does it reveal about Black-Scholes limitations?","back":"Implied volatility varies by strike price — OTM puts are priced with higher vol than ATM options (the ''skew''). This contradicts Black-Scholes'' constant-vol assumption and reflects market pricing of tail risk and jumps.","keyPoints":["Post-1987 crash: markets permanently price downside protection higher — the skew is a crash premium","The smile means the market implicitly uses a fatter-tailed distribution than lognormal for the underlying","Local volatility (Dupire): deterministic vol surface that fits the smile but has unrealistic dynamics","Stochastic volatility (Heston, SABR): vol itself is random — better dynamics but harder to calibrate"]}'),
(100, 'Core Formulas', 'What is the Expected Value formula, and when do you enter a trade?', '\(EV = (p_{win} \times profit) - (p_{loss} \times loss)\). Only enter when EV > 0. The top 1.2% of traders never enter negative EV — 87% of losers do.', '["Example: contract at $0.40, model says 55% → \\(EV = (0.55 \\times 0.60) - (0.45 \\times 0.40) = +\\$0.15\\)","EV ≤ 0 kills all strategies long-term — this is the single most important check","Prediction markets 2026 = retail on gut, mispricings last hours → EV edge exists"]', '{"id":100,"category":"Core Formulas","front":"What is the Expected Value formula, and when do you enter a trade?","back":"\\(EV = (p_{win} \\times profit) - (p_{loss} \\times loss)\\). Only enter when EV > 0. The top 1.2% of traders never enter negative EV — 87% of losers do.","keyPoints":["Example: contract at $0.40, model says 55% → \\(EV = (0.55 \\times 0.60) - (0.45 \\times 0.40) = +\\$0.15\\)","EV ≤ 0 kills all strategies long-term — this is the single most important check","Prediction markets 2026 = retail on gut, mispricings last hours → EV edge exists"]}'),
(101, 'Core Formulas', 'What is the Kelly Criterion, and why do pros use fractional Kelly?', '\(f^* = \frac{p \cdot b - q}{b}\), where p = win probability, q = 1−p, b = net payout. It gives the optimal fraction of bankroll to bet for maximum long-term growth.', '["Full Kelly is too aggressive — a bad run can wipe you out","Pros use ¼ to ½ Kelly for survivability","\\(2 \\times\\) Kelly = 0× long-run return (mathematically proven to go broke)","Example: 60% win, 2:1 payout → \\(f^* = \\frac{0.6 \\times 2 - 0.4}{2} = 0.40\\) (way too much — use 10-20%)"]', '{"id":101,"category":"Core Formulas","front":"What is the Kelly Criterion, and why do pros use fractional Kelly?","back":"\\(f^* = \\frac{p \\cdot b - q}{b}\\), where p = win probability, q = 1−p, b = net payout. It gives the optimal fraction of bankroll to bet for maximum long-term growth.","keyPoints":["Full Kelly is too aggressive — a bad run can wipe you out","Pros use ¼ to ½ Kelly for survivability","\\(2 \\times\\) Kelly = 0× long-run return (mathematically proven to go broke)","Example: 60% win, 2:1 payout → \\(f^* = \\frac{0.6 \\times 2 - 0.4}{2} = 0.40\\) (way too much — use 10-20%)"]}'),
(102, 'Core Formulas', 'How does Bayes'' Theorem apply to prediction markets?', '\(P(H|E) = \frac{P(E|H) \cdot P(H)}{P(E)}\). Update probability proportionally to new evidence — don''t overreact. Bots update faster than humans refresh Twitter.', '["Ceasefire contract at 30% → ''both sides agree to talks'' → Bayes → ~58% (not 90% panic)","Each piece of evidence nudges proportionally, it doesn''t replace","Start with base rate \\(P(H)\\), update with signal strength \\(P(E|H)\\)","Bayesian event arbitrage: update faster than market within a 3-minute window"]', '{"id":102,"category":"Core Formulas","front":"How does Bayes'' Theorem apply to prediction markets?","back":"\\(P(H|E) = \\frac{P(E|H) \\cdot P(H)}{P(E)}\\). Update probability proportionally to new evidence — don''t overreact. Bots update faster than humans refresh Twitter.","keyPoints":["Ceasefire contract at 30% → ''both sides agree to talks'' → Bayes → ~58% (not 90% panic)","Each piece of evidence nudges proportionally, it doesn''t replace","Start with base rate \\(P(H)\\), update with signal strength \\(P(E|H)\\)","Bayesian event arbitrage: update faster than market within a 3-minute window"]}'),
(103, 'Core Formulas', 'What is a base rate, and why does it matter more than narratives?', '\(P(A|signal) = \frac{TP}{TP + FP}\). The historical frequency of an event before any new information. Ignore narratives — look at denominators.', '["Incumbent approval > 50% → wins 82% of the time historically","If market prices this at 60%, there''s a 22-point gap = potential trade","Base rates anchor your prior; Bayes updates from there","Most losing traders skip base rates and trade on feelings"]', '{"id":103,"category":"Core Formulas","front":"What is a base rate, and why does it matter more than narratives?","back":"\\(P(A|signal) = \\frac{TP}{TP + FP}\\). The historical frequency of an event before any new information. Ignore narratives — look at denominators.","keyPoints":["Incumbent approval > 50% → wins 82% of the time historically","If market prices this at 60%, there''s a 22-point gap = potential trade","Base rates anchor your prior; Bayes updates from there","Most losing traders skip base rates and trade on feelings"]}'),
(104, 'Core Formulas', 'What is KL-Divergence and how does it find hidden arbitrage?', '\(D_{KL}(P \| Q) = \sum P_i \cdot \ln\frac{P_i}{Q_i}\). Measures how two probability distributions differ. Finds contracts that ''should'' be correlated but the market has mispriced.', '["''X wins nomination'' 70%, ''X wins general'' 55% — history says general should be ~62%","KL flags the gap → buy underpriced, hedge with other","Profit from convergence, not prediction","Scans for structural mispricings across correlated markets"]', '{"id":104,"category":"Core Formulas","front":"What is KL-Divergence and how does it find hidden arbitrage?","back":"\\(D_{KL}(P \\| Q) = \\sum P_i \\cdot \\ln\\frac{P_i}{Q_i}\\). Measures how two probability distributions differ. Finds contracts that ''should'' be correlated but the market has mispriced.","keyPoints":["''X wins nomination'' 70%, ''X wins general'' 55% — history says general should be ~62%","KL flags the gap → buy underpriced, hedge with other","Profit from convergence, not prediction","Scans for structural mispricings across correlated markets"]}'),
(105, 'Core Formulas', 'What is the Brier Score and how do you use it for calibration?', '\(BS = \frac{1}{n} \sum (f_t - o_t)^2\). Measures probability calibration. 0 = perfect oracle, 0.25 = coin flip. Polymarket averages ~0.0581 at 12 hours before resolution.', '["If your model''s Brier Score > market''s → stop directional bets, restrict to arbitrage","Track over time: improving score = model is learning; worsening = overfitting","Used in Superhuman Bot: triggers mode switch from directional to arb-only"]', '{"id":105,"category":"Core Formulas","front":"What is the Brier Score and how do you use it for calibration?","back":"\\(BS = \\frac{1}{n} \\sum (f_t - o_t)^2\\). Measures probability calibration. 0 = perfect oracle, 0.25 = coin flip. Polymarket averages ~0.0581 at 12 hours before resolution.","keyPoints":["If your model''s Brier Score > market''s → stop directional bets, restrict to arbitrage","Track over time: improving score = model is learning; worsening = overfitting","Used in Superhuman Bot: triggers mode switch from directional to arb-only"]}'),
(110, 'Strategies', 'What are the only 3 strategies that survived 10,000 Polymarket simulations?', 'Insurance Model (71.4% survival), Sports O/U Quant (68.9%), and Bayesian Event Arbitrage (64.2%). 9,710 of 10,000 simulated traders went broke.', '["Insurance: sell ''No'' at 88–98¢ (e.g. LucasMeow: 148-0 record, $275K profit)","Sports O/U: statistical model on game totals, entry only when edge > 5%","Bayesian Arb: update probability faster than market in a 3-minute window","4 properties predict survival: positive EV on every entry, Kelly sizing, model-first, structural edge"]', '{"id":110,"category":"Strategies","front":"What are the only 3 strategies that survived 10,000 Polymarket simulations?","back":"Insurance Model (71.4% survival), Sports O/U Quant (68.9%), and Bayesian Event Arbitrage (64.2%). 9,710 of 10,000 simulated traders went broke.","keyPoints":["Insurance: sell ''No'' at 88–98¢ (e.g. LucasMeow: 148-0 record, $275K profit)","Sports O/U: statistical model on game totals, entry only when edge > 5%","Bayesian Arb: update probability faster than market in a 3-minute window","4 properties predict survival: positive EV on every entry, Kelly sizing, model-first, structural edge"]}'),
(111, 'Strategies', 'Why do momentum trading, gut feeling, blind copy-trading, and spread arbitrage all fail?', 'All have EV ≤ 0 at scale. Momentum: 94.2% death rate (LMSR prices instantly). Gut: 91.7% (public info priced in). Copy: 88.3% (edge decays before fill). Spread arb: 79.1% (slippage eats profit).', '["The unifying killer: EV ≤ 0 destroys all strategies eventually","Copy-trading fails because you can''t clone another trader''s edge (quantum no-cloning analogy)","Spread arbitrage only works with institutional-grade execution infrastructure"]', '{"id":111,"category":"Strategies","front":"Why do momentum trading, gut feeling, blind copy-trading, and spread arbitrage all fail?","back":"All have EV ≤ 0 at scale. Momentum: 94.2% death rate (LMSR prices instantly). Gut: 91.7% (public info priced in). Copy: 88.3% (edge decays before fill). Spread arb: 79.1% (slippage eats profit).","keyPoints":["The unifying killer: EV ≤ 0 destroys all strategies eventually","Copy-trading fails because you can''t clone another trader''s edge (quantum no-cloning analogy)","Spread arbitrage only works with institutional-grade execution infrastructure"]}'),
(112, 'Strategies', 'How does market making work on prediction markets?', 'Post bid below fair price, ask above it → capture the spread. Use inventory skew to rebalance: accumulated YES position → raise ask, lower bid. Profit without predicting outcomes.', '["Example: bid $0.48, ask $0.52 → collect $0.04 per round-trip","Reservation price adjusts dynamically based on inventory exposure","Monitor VPIN for toxic flow: VPIN > 0.70 → exit immediately","\\(VPIN = \\frac{|V_{buy} - V_{sell}|}{V_{buy} + V_{sell}}\\) — measures informed trading"]', '{"id":112,"category":"Strategies","front":"How does market making work on prediction markets?","back":"Post bid below fair price, ask above it → capture the spread. Use inventory skew to rebalance: accumulated YES position → raise ask, lower bid. Profit without predicting outcomes.","keyPoints":["Example: bid $0.48, ask $0.52 → collect $0.04 per round-trip","Reservation price adjusts dynamically based on inventory exposure","Monitor VPIN for toxic flow: VPIN > 0.70 → exit immediately","\\(VPIN = \\frac{|V_{buy} - V_{sell}|}{V_{buy} + V_{sell}}\\) — measures informed trading"]}'),
(113, 'Strategies', 'How does pairs/spread trading work with cointegrated contracts?', 'Find two logically related contracts (e.g. ''Fed cuts March?'' and ''Fed cuts June?''). Calculate beta, test cointegration (Engle-Granger), trade when z-score > 2.0 and Gaussian Process confirms mean reversion.', '["Beta: if June +10%, March should move +4.5% (beta=0.45). If only +2%, gap exists","Engle-Granger test: p-value < 0.05 → real connection; > 0.05 → coincidence, skip","Three conditions: cointegrated (p<0.05) + large gap (|z|>2.0) + GP confirms return","Result: $10K-$20K monthly profit without predicting direction"]', '{"id":113,"category":"Strategies","front":"How does pairs/spread trading work with cointegrated contracts?","back":"Find two logically related contracts (e.g. ''Fed cuts March?'' and ''Fed cuts June?''). Calculate beta, test cointegration (Engle-Granger), trade when z-score > 2.0 and Gaussian Process confirms mean reversion.","keyPoints":["Beta: if June +10%, March should move +4.5% (beta=0.45). If only +2%, gap exists","Engle-Granger test: p-value < 0.05 → real connection; > 0.05 → coincidence, skip","Three conditions: cointegrated (p<0.05) + large gap (|z|>2.0) + GP confirms return","Result: $10K-$20K monthly profit without predicting direction"]}'),
(114, 'Strategies', 'How does the Insurance Model strategy work?', 'Sell ''No'' contracts at 88–98¢ on events extremely unlikely to happen. You collect small premiums repeatedly. Like selling insurance — small consistent profit, rare catastrophic loss.', '["LucasMeow: 148-0 record, $275K profit using this strategy","71.4% survival rate in 10,000 simulations (best of all strategies)","Key risk: tail events — the rare loss can be huge","Requires strict position sizing and diversification across many markets"]', '{"id":114,"category":"Strategies","front":"How does the Insurance Model strategy work?","back":"Sell ''No'' contracts at 88–98¢ on events extremely unlikely to happen. You collect small premiums repeatedly. Like selling insurance — small consistent profit, rare catastrophic loss.","keyPoints":["LucasMeow: 148-0 record, $275K profit using this strategy","71.4% survival rate in 10,000 simulations (best of all strategies)","Key risk: tail events — the rare loss can be huge","Requires strict position sizing and diversification across many markets"]}');
INSERT INTO cards (id, category, front, back, key_points, data) VALUES
(120, 'Infrastructure', 'What is Polymarket''s market structure?', 'Polymarket is a CLOB (Central Limit Order Book), NOT an LMSR (Logarithmic Market Scoring Rule). Binary constraint: YES + NO must sum to $1.00.', '["CLOB: matching engine like traditional exchanges (bid/ask, depth, spread)","If YES $0.47 + NO $0.50 = $0.97 → buy both for $0.97, collect $1.00 → 3¢ per dollar","API: Gamma (discovery) + CLOB (trading), REST or WebSocket","Gas on Polygon: ~$0.007 per transaction (negligible)"]', '{"id":120,"category":"Infrastructure","front":"What is Polymarket''s market structure?","back":"Polymarket is a CLOB (Central Limit Order Book), NOT an LMSR (Logarithmic Market Scoring Rule). Binary constraint: YES + NO must sum to $1.00.","keyPoints":["CLOB: matching engine like traditional exchanges (bid/ask, depth, spread)","If YES $0.47 + NO $0.50 = $0.97 → buy both for $0.97, collect $1.00 → 3¢ per dollar","API: Gamma (discovery) + CLOB (trading), REST or WebSocket","Gas on Polygon: ~$0.007 per transaction (negligible)"]}'),
(121, 'Infrastructure', 'What is VPIN and why is it a critical risk signal?', 'Volume-Synchronized Probability of Informed Trading: \(VPIN = \frac{|V_{buy} - V_{sell}|}{V_{buy} + V_{sell}}\). Measures whether informed traders are active. High VPIN = toxic flow = danger for market makers.', '["VPIN > 0.70 → toxic flow, exit market-making positions immediately","Low VPIN → safe to provide liquidity and capture spread","Acts as a kill switch: real-time monitoring prevents catastrophic losses","Informed traders move before public news → VPIN detects the imbalance"]', '{"id":121,"category":"Infrastructure","front":"What is VPIN and why is it a critical risk signal?","back":"Volume-Synchronized Probability of Informed Trading: \\(VPIN = \\frac{|V_{buy} - V_{sell}|}{V_{buy} + V_{sell}}\\). Measures whether informed traders are active. High VPIN = toxic flow = danger for market makers.","keyPoints":["VPIN > 0.70 → toxic flow, exit market-making positions immediately","Low VPIN → safe to provide liquidity and capture spread","Acts as a kill switch: real-time monitoring prevents catastrophic losses","Informed traders move before public news → VPIN detects the imbalance"]}'),
(122, 'Infrastructure', 'What are the four components of an arbitrage system?', 'Data Collector (WebSocket order book), Strategy Engine (YES + NO check every tick), Order Manager (FOK execution, retry, rate limits), Risk Manager (exposure tracking, kill switch).', '["Fill-or-Kill (FOK) orders: both sides execute together or neither does — prevents unhedged exposure","Rate limit: 60 orders/min on Polymarket CLOB API","Keep single market exposure < 5% of total book","SDKs: Python (py-clob-client), TypeScript (@polymarket/clob-client), Rust (lowest latency)"]', '{"id":122,"category":"Infrastructure","front":"What are the four components of an arbitrage system?","back":"Data Collector (WebSocket order book), Strategy Engine (YES + NO check every tick), Order Manager (FOK execution, retry, rate limits), Risk Manager (exposure tracking, kill switch).","keyPoints":["Fill-or-Kill (FOK) orders: both sides execute together or neither does — prevents unhedged exposure","Rate limit: 60 orders/min on Polymarket CLOB API","Keep single market exposure < 5% of total book","SDKs: Python (py-clob-client), TypeScript (@polymarket/clob-client), Rust (lowest latency)"]}'),
(130, 'Order Books', 'How do you read an order book and what do limit vs. market orders do?', 'Bids (buy) on left at prices ≤ current. Asks (sell) on right at prices ≥ current. Limit orders create liquidity (walls). Market orders consume liquidity (cross the spread).', '["Large limit orders at key levels = supply/demand zones (more reliable than TA alone)","Thick book = high liquidity = hard to move price","Thin book = low liquidity = easy to move price, strong momentum effects","Avoid Binance Perpetuals for book analysis — massive spoofing with 1000+ BTC orders"]', '{"id":130,"category":"Order Books","front":"How do you read an order book and what do limit vs. market orders do?","back":"Bids (buy) on left at prices ≤ current. Asks (sell) on right at prices ≥ current. Limit orders create liquidity (walls). Market orders consume liquidity (cross the spread).","keyPoints":["Large limit orders at key levels = supply/demand zones (more reliable than TA alone)","Thick book = high liquidity = hard to move price","Thin book = low liquidity = easy to move price, strong momentum effects","Avoid Binance Perpetuals for book analysis — massive spoofing with 1000+ BTC orders"]}'),
(131, 'Order Books', 'What is depth delta and how does it signal reversals?', 'Depth delta = total bid volume − total ask volume in a price range. Positive delta (more bids) = buying pressure. Significant imbalances signal potential reversals.', '["Example: 550 bids vs 350 asks in 0-10% range → delta = +200 (bullish)","Recommended depth ranges: 2.5% and 5% (intraday), 10% (larger moves)","Depth is a lagging indicator — reflects where liquidity is building, not where price goes next","Best on Binance Spot and Coinbase (deepest, most reliable liquidity)"]', '{"id":131,"category":"Order Books","front":"What is depth delta and how does it signal reversals?","back":"Depth delta = total bid volume − total ask volume in a price range. Positive delta (more bids) = buying pressure. Significant imbalances signal potential reversals.","keyPoints":["Example: 550 bids vs 350 asks in 0-10% range → delta = +200 (bullish)","Recommended depth ranges: 2.5% and 5% (intraday), 10% (larger moves)","Depth is a lagging indicator — reflects where liquidity is building, not where price goes next","Best on Binance Spot and Coinbase (deepest, most reliable liquidity)"]}'),
(132, 'Order Books', 'How do order book heatmaps work and what patterns should you look for?', 'Heatmaps visualize resting limit orders over time on the price chart. Red lines = large sell walls (resistance). Green lines = large buy walls (support). Shows where big players accumulate or defend.', '["Price repeatedly testing a wall without breaking = strong defense","Sudden appearance of walls near price = institutions positioning","Use filter slider to hide market-maker noise, focus on large orders","Depth overlay displays liquidity directly on price candles (green bands = support, red = resistance)"]', '{"id":132,"category":"Order Books","front":"How do order book heatmaps work and what patterns should you look for?","back":"Heatmaps visualize resting limit orders over time on the price chart. Red lines = large sell walls (resistance). Green lines = large buy walls (support). Shows where big players accumulate or defend.","keyPoints":["Price repeatedly testing a wall without breaking = strong defense","Sudden appearance of walls near price = institutions positioning","Use filter slider to hide market-maker noise, focus on large orders","Depth overlay displays liquidity directly on price candles (green bands = support, red = resistance)"]}'),
(140, 'Validation', 'Why is one backtest meaningless, and how does bootstrap simulation fix this?', 'One backtest could be luck. Bootstrap: sample trades with replacement 10,000 times to build a distribution of possible outcomes. If the 95% confidence interval excludes 50%, the edge is likely real.', '["CI = np.percentile(results, [2.5, 97.5])","Example result: win rate CI [87.3%, 91.8%] — far from 50% → real edge","If CI includes 50% → coin flip, no edge","Every metric gets a CI: win rate, Sharpe, max drawdown"]', '{"id":140,"category":"Validation","front":"Why is one backtest meaningless, and how does bootstrap simulation fix this?","back":"One backtest could be luck. Bootstrap: sample trades with replacement 10,000 times to build a distribution of possible outcomes. If the 95% confidence interval excludes 50%, the edge is likely real.","keyPoints":["CI = np.percentile(results, [2.5, 97.5])","Example result: win rate CI [87.3%, 91.8%] — far from 50% → real edge","If CI includes 50% → coin flip, no edge","Every metric gets a CI: win rate, Sharpe, max drawdown"]}'),
(141, 'Validation', 'How do Markov chains model contract state transitions?', 'States: low (0-30%), mid (30-60%), high (60-90%), resolved (100%). Transition matrix gives probability of moving between states. Use to predict contract trajectory.', '["Contract at 28% (low) → 60% chance stays low, 30% to mid, 8% to high, 2% resolves","Buy signal: contract price ≤ p_resolve_yes × 0.5 (market underpricing resolution probability)","Burn-in: first ~1000 steps unreliable — don''t trade newly listed contracts (wait 48-72 hours)","Combine with bootstrap: Markov predicts trajectory, bootstrap validates edge"]', '{"id":141,"category":"Validation","front":"How do Markov chains model contract state transitions?","back":"States: low (0-30%), mid (30-60%), high (60-90%), resolved (100%). Transition matrix gives probability of moving between states. Use to predict contract trajectory.","keyPoints":["Contract at 28% (low) → 60% chance stays low, 30% to mid, 8% to high, 2% resolves","Buy signal: contract price ≤ p_resolve_yes × 0.5 (market underpricing resolution probability)","Burn-in: first ~1000 steps unreliable — don''t trade newly listed contracts (wait 48-72 hours)","Combine with bootstrap: Markov predicts trajectory, bootstrap validates edge"]}'),
(142, 'Validation', 'Why is win rate a trap on Polymarket?', 'At $0.77 YES, you risk $0.77 to win $0.23 (3.3:1 against). A single loss wipes out 3 wins. 77% win rate barely breaks even. Only 16.8% of Polymarket wallets show any net gain.', '["Ghost positions: losers held at near-zero artificially inflate win rate","52% win rate + $1.3M realized PnL >>> 85% win rate + $30K realized PnL","What actually matters: absolute realized PnL, PnL by category, position size consistency","Copy-trading minimum: 50+ resolved trades, no single trade = 70%+ of total PnL"]', '{"id":142,"category":"Validation","front":"Why is win rate a trap on Polymarket?","back":"At $0.77 YES, you risk $0.77 to win $0.23 (3.3:1 against). A single loss wipes out 3 wins. 77% win rate barely breaks even. Only 16.8% of Polymarket wallets show any net gain.","keyPoints":["Ghost positions: losers held at near-zero artificially inflate win rate","52% win rate + $1.3M realized PnL >>> 85% win rate + $30K realized PnL","What actually matters: absolute realized PnL, PnL by category, position size consistency","Copy-trading minimum: 50+ resolved trades, no single trade = 70%+ of total PnL"]}'),
(150, 'Sentiment', 'How does adding fear/sentiment to a trading model work, and what''s the critical insight?', 'Layer VIX + CNN Fear & Greed Index + social sentiment. Critical insight: not all contracts react to fear the same way. You must calculate a sensitivity factor per contract.', '["''Will there be recession?'' → Fear ↑ → YES price ↑ (correlated)","''Will Fed raise rates?'' → Fear ↑ → YES price ↓ (anti-correlated)","Sensitivity = 60-day backward correlation between price changes and fear/greed","Without sensitivity factor: baseline barely beaten. With it: $5K → $18K (backtest)"]', '{"id":150,"category":"Sentiment","front":"How does adding fear/sentiment to a trading model work, and what''s the critical insight?","back":"Layer VIX + CNN Fear & Greed Index + social sentiment. Critical insight: not all contracts react to fear the same way. You must calculate a sensitivity factor per contract.","keyPoints":["''Will there be recession?'' → Fear ↑ → YES price ↑ (correlated)","''Will Fed raise rates?'' → Fear ↑ → YES price ↓ (anti-correlated)","Sensitivity = 60-day backward correlation between price changes and fear/greed","Without sensitivity factor: baseline barely beaten. With it: $5K → $18K (backtest)"]}'),
(151, 'Sentiment', 'What are the entry rules for a fear-based trading model?', 'Extreme Fear (FGI < 20): buy underpriced YES when model_prob − price > 0.15. Extreme Greed (FGI > 80): sell overpriced YES when price − model_prob > 0.15. Neutral: only enter on strong signal (model_prob ≥ 0.65, price ≤ 0.5 × model_prob).', '["Three fear layers: VIX (surface), CNN FGI (middle), Reddit/Twitter (depth — noisiest but earliest)","CNN FGI: 0-100 scale, data since 2011, updates daily","VIX rolling averages (10d, 20d, 30d) smooth noise","Neutral zone (20-80) requires much higher conviction to enter"]', '{"id":151,"category":"Sentiment","front":"What are the entry rules for a fear-based trading model?","back":"Extreme Fear (FGI < 20): buy underpriced YES when model_prob − price > 0.15. Extreme Greed (FGI > 80): sell overpriced YES when price − model_prob > 0.15. Neutral: only enter on strong signal (model_prob ≥ 0.65, price ≤ 0.5 × model_prob).","keyPoints":["Three fear layers: VIX (surface), CNN FGI (middle), Reddit/Twitter (depth — noisiest but earliest)","CNN FGI: 0-100 scale, data since 2011, updates daily","VIX rolling averages (10d, 20d, 30d) smooth noise","Neutral zone (20-80) requires much higher conviction to enter"]}'),
(160, 'AI/ML', 'How does MiroFish use multi-agent simulation for prediction markets?', 'Build a knowledge graph from real-world data → generate AI agent personas → simulate social interaction on a virtual platform → extract emergent probability estimates from convergent opinions.', '["Stack: GPT-4o mini + Zep Cloud (memory) + OASIS engine (CAMEL-AI)","200 agents with distinct personas (governments, traders, media, military)","Organic posting more reliable than formal interviews (cooperation bias in interviews)","Cost: $3-5 per simulation run, ~49 minutes on Mac Mini M4 Pro"]', '{"id":160,"category":"AI/ML","front":"How does MiroFish use multi-agent simulation for prediction markets?","back":"Build a knowledge graph from real-world data → generate AI agent personas → simulate social interaction on a virtual platform → extract emergent probability estimates from convergent opinions.","keyPoints":["Stack: GPT-4o mini + Zep Cloud (memory) + OASIS engine (CAMEL-AI)","200 agents with distinct personas (governments, traders, media, military)","Organic posting more reliable than formal interviews (cooperation bias in interviews)","Cost: $3-5 per simulation run, ~49 minutes on Mac Mini M4 Pro"]}'),
(161, 'AI/ML', 'How do poker AI algorithms (CFR+, DeepStack, Libratus) apply to market arbitrage?', 'Prediction markets are imperfect information games like poker. CFR+ minimizes regret across strategies. DeepStack uses neural networks for real-time subgame solving. Libratus handles off-tree scenarios.', '["CFR+: reset negative regret to zero, weight later iterations more (converges to Nash equilibrium)","DeepStack: local strategy computation requiring minimal memory, neural net provides ''intuition''","Libratus: constructs new detailed subgames in real-time for unseen situations","Marginal polytope: if market prices fall outside valid probability space → arbitrage exists"]', '{"id":161,"category":"AI/ML","front":"How do poker AI algorithms (CFR+, DeepStack, Libratus) apply to market arbitrage?","back":"Prediction markets are imperfect information games like poker. CFR+ minimizes regret across strategies. DeepStack uses neural networks for real-time subgame solving. Libratus handles off-tree scenarios.","keyPoints":["CFR+: reset negative regret to zero, weight later iterations more (converges to Nash equilibrium)","DeepStack: local strategy computation requiring minimal memory, neural net provides ''intuition''","Libratus: constructs new detailed subgames in real-time for unseen situations","Marginal polytope: if market prices fall outside valid probability space → arbitrage exists"]}'),
(162, 'AI/ML', 'What''s the 6-month progression from zero to autonomous trading agent?', 'Month 1: probability thinking (track 30 predictions). Month 2: core formulas (EV, Kelly, base rates). Month 3: ML model (Random Forest, 38 features). Month 4: validation (bootstrap, Markov). Month 5: XGBoost (330 trees). Month 6: RL agent (PPO).', '["Month 1 formula: edge = real_probability − market_price","Month 3: 100 decision trees, 38 features → target 80%+ win rate on unseen data","Month 5: XGBoost loss 0.891 → 0.094 after 330 cycles → 89.6% win rate","Month 6: PPO with 50,000 historical trades, reward = pnl × contract_payout"]', '{"id":162,"category":"AI/ML","front":"What''s the 6-month progression from zero to autonomous trading agent?","back":"Month 1: probability thinking (track 30 predictions). Month 2: core formulas (EV, Kelly, base rates). Month 3: ML model (Random Forest, 38 features). Month 4: validation (bootstrap, Markov). Month 5: XGBoost (330 trees). Month 6: RL agent (PPO).","keyPoints":["Month 1 formula: edge = real_probability − market_price","Month 3: 100 decision trees, 38 features → target 80%+ win rate on unseen data","Month 5: XGBoost loss 0.891 → 0.094 after 330 cycles → 89.6% win rate","Month 6: PPO with 50,000 historical trades, reward = pnl × contract_payout"]}'),
(170, 'Quantum Framework', 'How does the quantum mechanics analogy apply to prediction markets?', 'Contract = spin-1/2 system. Price = squared amplitude of YES state. Same price can have different ''phases'' (momentum, liquidity context). Markets behave quantum-like far from resolution, classical near it.', '["State vector: \\(|market\\rangle = \\sqrt{p}\\,|YES\\rangle + \\sqrt{1-p}\\,|NO\\rangle\\)","Bloch sphere: polar angle \\(\\theta\\) → price, azimuthal angle \\(\\phi\\) → market context (hidden in price alone)","Entanglement: correlated markets update simultaneously when one resolves","Decoherence: far from resolution → quantum effects dominate; near resolution → classical convergence"]', '{"id":170,"category":"Quantum Framework","front":"How does the quantum mechanics analogy apply to prediction markets?","back":"Contract = spin-1/2 system. Price = squared amplitude of YES state. Same price can have different ''phases'' (momentum, liquidity context). Markets behave quantum-like far from resolution, classical near it.","keyPoints":["State vector: \\(|market\\rangle = \\sqrt{p}\\,|YES\\rangle + \\sqrt{1-p}\\,|NO\\rangle\\)","Bloch sphere: polar angle \\(\\theta\\) → price, azimuthal angle \\(\\phi\\) → market context (hidden in price alone)","Entanglement: correlated markets update simultaneously when one resolves","Decoherence: far from resolution → quantum effects dominate; near resolution → classical convergence"]}'),
(171, 'Quantum Framework', 'What is the Market Uncertainty Principle?', 'You can''t simultaneously know fair price AND momentum with arbitrary precision. Liquid markets → known price, zero predictive momentum (random walk). Thin markets → uncertain price, strong extractable momentum.', '["\\(\\Delta Price \\times \\Delta Momentum \\geq constant\\)","Implication: edge lives in thinner, less efficient markets","Quantum edge exists in longer-dated markets (pre-decoherence)","Information = rotation on Bloch sphere (axis = type, angle = magnitude)"]', '{"id":171,"category":"Quantum Framework","front":"What is the Market Uncertainty Principle?","back":"You can''t simultaneously know fair price AND momentum with arbitrary precision. Liquid markets → known price, zero predictive momentum (random walk). Thin markets → uncertain price, strong extractable momentum.","keyPoints":["\\(\\Delta Price \\times \\Delta Momentum \\geq constant\\)","Implication: edge lives in thinner, less efficient markets","Quantum edge exists in longer-dated markets (pre-decoherence)","Information = rotation on Bloch sphere (axis = type, angle = magnitude)"]}'),
(172, 'Quantum Framework', 'Why are prediction markets not purely Bayesian, and how does interference explain this?', 'Quantum interference: amplitudes of different paths add before squaring. Two paths to same outcome can cancel or amplify each other. Classical probability (Bayesian) misses these nonlinear, context-dependent correlations.', '["''Will Company X be acquired?'' — two paths: strategic buyer vs. PE buyout","PE less likely IF strategic buyer emerges (destructive interference / cancellation)","Classical: P(acquired) = P(strategic) + P(PE). Quantum: amplitudes add, then square","No-cloning theorem: can''t perfectly replicate another trader''s edge (copy-trading = noisy approximation)"]', '{"id":172,"category":"Quantum Framework","front":"Why are prediction markets not purely Bayesian, and how does interference explain this?","back":"Quantum interference: amplitudes of different paths add before squaring. Two paths to same outcome can cancel or amplify each other. Classical probability (Bayesian) misses these nonlinear, context-dependent correlations.","keyPoints":["''Will Company X be acquired?'' — two paths: strategic buyer vs. PE buyout","PE less likely IF strategic buyer emerges (destructive interference / cancellation)","Classical: P(acquired) = P(strategic) + P(PE). Quantum: amplitudes add, then square","No-cloning theorem: can''t perfectly replicate another trader''s edge (copy-trading = noisy approximation)"]}'),
(180, 'Weather Bot', 'How does a self-calibrating Polymarket weather bot work?', 'Aggregate 3 forecast sources (ECMWF, HRRR/GFS, METAR), compare against market prices, calculate EV, size with fractional Kelly (0.25), and self-calibrate after 30+ resolved markets per city.', '["EV = p × (1.0/price − 1.0) − (1.0 − p). Example: p=0.80, price=$0.14 → EV = +4.94","Use airport ICAO station coordinates (KLGA, KORD), not city center","Calibration: MAE per forecast source per city → becomes sigma for normal distribution","Stops: -20% stop-loss, trailing stop, forecast stop if >2°F/1°C shift out of bought bucket"]', '{"id":180,"category":"Weather Bot","front":"How does a self-calibrating Polymarket weather bot work?","back":"Aggregate 3 forecast sources (ECMWF, HRRR/GFS, METAR), compare against market prices, calculate EV, size with fractional Kelly (0.25), and self-calibrate after 30+ resolved markets per city.","keyPoints":["EV = p × (1.0/price − 1.0) − (1.0 − p). Example: p=0.80, price=$0.14 → EV = +4.94","Use airport ICAO station coordinates (KLGA, KORD), not city center","Calibration: MAE per forecast source per city → becomes sigma for normal distribution","Stops: -20% stop-loss, trailing stop, forecast stop if >2°F/1°C shift out of bought bucket"]}'),
(190, 'Edge Theory', 'What are the 7 categories of market edges, and how do you stack them?', 'Broker/execution, factor (academic), information, strategy/process, structural, volatility, and time-based (calendar). Stack multiple for compounding advantage.', '["Structural: crypto liquidation cascades → forced selling → snap-back (use Coinglass to monitor)","Volatility Risk Premium: selling options works 85% of the time, but the 15% can blow you up","Time-based: turn-of-month effect, January effect, sell in May","Stacking: tested system + low commissions + turn-of-month + domain expertise = compounding edge"]', '{"id":190,"category":"Edge Theory","front":"What are the 7 categories of market edges, and how do you stack them?","back":"Broker/execution, factor (academic), information, strategy/process, structural, volatility, and time-based (calendar). Stack multiple for compounding advantage.","keyPoints":["Structural: crypto liquidation cascades → forced selling → snap-back (use Coinglass to monitor)","Volatility Risk Premium: selling options works 85% of the time, but the 15% can blow you up","Time-based: turn-of-month effect, January effect, sell in May","Stacking: tested system + low commissions + turn-of-month + domain expertise = compounding edge"]}'),
(191, 'Edge Theory', 'What are the 4 properties that predict long-term survival in prediction markets?', '1) Positive EV on EVERY entry (no exceptions). 2) Kelly Criterion position sizing. 3) Model-first, never intuition-first. 4) Edge has a structural reason (not historical luck).', '["From 10,000 simulations: 97.1% of traders went broke","Top survivors: Bayesian arb +1240%, Sports O/U +890%, Insurance +340%","2× Kelly = guaranteed long-term ruin (mathematical certainty)","If you can''t explain WHY the edge exists structurally, it''s probably luck"]', '{"id":191,"category":"Edge Theory","front":"What are the 4 properties that predict long-term survival in prediction markets?","back":"1) Positive EV on EVERY entry (no exceptions). 2) Kelly Criterion position sizing. 3) Model-first, never intuition-first. 4) Edge has a structural reason (not historical luck).","keyPoints":["From 10,000 simulations: 97.1% of traders went broke","Top survivors: Bayesian arb +1240%, Sports O/U +890%, Insurance +340%","2× Kelly = guaranteed long-term ruin (mathematical certainty)","If you can''t explain WHY the edge exists structurally, it''s probably luck"]}'),
(200, 'EV Practice', 'A contract costs $0.40. Your model says 55% chance YES. What is the Expected Value?', '\(EV = (0.55 \times 0.60) - (0.45 \times 0.40) = 0.33 - 0.18 = +0.15\)', '["Profit if YES = \\(1.00 - 0.40 = 0.60\\)","Loss if NO = \\(0.40\\) (your cost)","EV > 0 means this is a good trade"]', '{"id":200,"category":"EV Practice","exerciseType":"math","front":"A contract costs $0.40. Your model says 55% chance YES. What is the Expected Value?","back":"\\(EV = (0.55 \\times 0.60) - (0.45 \\times 0.40) = 0.33 - 0.18 = +0.15\\)","keyPoints":["Profit if YES = \\(1.00 - 0.40 = 0.60\\)","Loss if NO = \\(0.40\\) (your cost)","EV > 0 means this is a good trade"],"mathAnswer":0.15,"tolerance":0.02,"unit":"$","hints":["Profit if YES = $1.00 − $0.40 = $0.60","EV = (win_prob × profit) − (loss_prob × loss)"]}'),
(201, 'EV Practice', 'A contract costs $0.72. Your model says 65% chance YES. What is the EV?', '\(EV = (0.65 \times 0.28) - (0.35 \times 0.72) = 0.182 - 0.252 = -0.07\)', '["Profit if YES = \\(1.00 - 0.72 = 0.28\\)","Negative EV — do NOT enter this trade","Even at 65% probability, the risk/reward ratio is bad here"]', '{"id":201,"category":"EV Practice","exerciseType":"math","front":"A contract costs $0.72. Your model says 65% chance YES. What is the EV?","back":"\\(EV = (0.65 \\times 0.28) - (0.35 \\times 0.72) = 0.182 - 0.252 = -0.07\\)","keyPoints":["Profit if YES = \\(1.00 - 0.72 = 0.28\\)","Negative EV — do NOT enter this trade","Even at 65% probability, the risk/reward ratio is bad here"],"mathAnswer":-0.07,"tolerance":0.02,"unit":"$","hints":["Profit if YES = $1.00 − $0.72 = $0.28"]}'),
(202, 'EV Practice', 'Contract at $0.25. Your model says 40% chance YES. What is the EV?', '\(EV = (0.40 \times 0.75) - (0.60 \times 0.25) = 0.30 - 0.15 = +0.15\)', '["Cheap contracts can have great EV even at sub-50% probability","The asymmetric payoff (risk $0.25 to win $0.75) creates edge"]', '{"id":202,"category":"EV Practice","exerciseType":"math","front":"Contract at $0.25. Your model says 40% chance YES. What is the EV?","back":"\\(EV = (0.40 \\times 0.75) - (0.60 \\times 0.25) = 0.30 - 0.15 = +0.15\\)","keyPoints":["Cheap contracts can have great EV even at sub-50% probability","The asymmetric payoff (risk $0.25 to win $0.75) creates edge"],"mathAnswer":0.15,"tolerance":0.02,"unit":"$"}'),
(203, 'EV Practice', 'You can buy YES at $0.30 and NO at $0.65. They must sum to $1.00 at resolution. What is the arbitrage profit per contract pair?', 'Cost = \(0.30 + 0.65 = 0.95\). Payout = \(1.00\). Profit = \(1.00 - 0.95 = 0.05\).', '["When YES + NO < $1.00, guaranteed profit exists","No prediction needed — this is pure structural arbitrage"]', '{"id":203,"category":"EV Practice","exerciseType":"math","front":"You can buy YES at $0.30 and NO at $0.65. They must sum to $1.00 at resolution. What is the arbitrage profit per contract pair?","back":"Cost = \\(0.30 + 0.65 = 0.95\\). Payout = \\(1.00\\). Profit = \\(1.00 - 0.95 = 0.05\\).","keyPoints":["When YES + NO < $1.00, guaranteed profit exists","No prediction needed — this is pure structural arbitrage"],"mathAnswer":0.05,"tolerance":0.01,"unit":"$"}'),
(204, 'Kelly Practice', 'Win probability = 60%, net payout = 2:1. What is the full Kelly fraction?', '\(f^* = \frac{p \cdot b - q}{b} = \frac{0.6 \times 2 - 0.4}{2} = \frac{0.8}{2} = 0.40\)', '["p = 0.60, q = 0.40, b = 2","Full Kelly says bet 40% of bankroll — dangerously aggressive","At quarter-Kelly (10%), you sacrifice ~25% of growth for much lower ruin risk"]', '{"id":204,"category":"Kelly Practice","exerciseType":"math","front":"Win probability = 60%, net payout = 2:1. What is the full Kelly fraction?","back":"\\(f^* = \\frac{p \\cdot b - q}{b} = \\frac{0.6 \\times 2 - 0.4}{2} = \\frac{0.8}{2} = 0.40\\)","keyPoints":["p = 0.60, q = 0.40, b = 2","Full Kelly says bet 40% of bankroll — dangerously aggressive","At quarter-Kelly (10%), you sacrifice ~25% of growth for much lower ruin risk"],"mathAnswer":0.4,"tolerance":0.02,"hints":["\\(f^* = \\frac{p \\cdot b - q}{b}\\) where q = 1 − p"]}'),
(205, 'Kelly Practice', 'Full Kelly says 40%. Using quarter-Kelly, what fraction of your bankroll should you risk?', '\(\frac{1}{4} \times 0.40 = 0.10\) — risk 10% of bankroll.', '["Quarter-Kelly is the standard for professional traders","Sacrifices ~25% of theoretical growth rate for dramatically lower ruin probability"]', '{"id":205,"category":"Kelly Practice","exerciseType":"math","front":"Full Kelly says 40%. Using quarter-Kelly, what fraction of your bankroll should you risk?","back":"\\(\\frac{1}{4} \\times 0.40 = 0.10\\) — risk 10% of bankroll.","keyPoints":["Quarter-Kelly is the standard for professional traders","Sacrifices ~25% of theoretical growth rate for dramatically lower ruin probability"],"mathAnswer":0.1,"tolerance":0.01}'),
(206, 'Kelly Practice', 'Win probability = 55%, net payout = 1:1. What is the full Kelly fraction?', '\(f^* = \frac{0.55 \times 1 - 0.45}{1} = \frac{0.10}{1} = 0.10\)', '["Even with an edge, Kelly is small for 1:1 payouts","55/45 edge at 1:1 odds → only risk 10%","This is why pros rarely bet big on coin-flip-like events"]', '{"id":206,"category":"Kelly Practice","exerciseType":"math","front":"Win probability = 55%, net payout = 1:1. What is the full Kelly fraction?","back":"\\(f^* = \\frac{0.55 \\times 1 - 0.45}{1} = \\frac{0.10}{1} = 0.10\\)","keyPoints":["Even with an edge, Kelly is small for 1:1 payouts","55/45 edge at 1:1 odds → only risk 10%","This is why pros rarely bet big on coin-flip-like events"],"mathAnswer":0.1,"tolerance":0.02,"hints":["b = 1 for even-money bets"]}'),
(207, 'Bayes Practice', 'Prior P(ceasefire) = 0.30. If ceasefire happens, P(talks) = 0.85. If no ceasefire, P(talks) = 0.20. Talks are announced. What is P(ceasefire | talks)?', '\(P(E) = 0.85 \times 0.30 + 0.20 \times 0.70 = 0.255 + 0.14 = 0.395\)
INSERT INTO cards (id, category, front, back, key_points, data) VALUES
(1007, 'Greetings', 'de rien', 'you''re welcome', '["Literally ''of nothing''","Also: ''je vous en prie'' (formal)"]', '{"id":1007,"category":"Greetings","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"de rien","back":"you''re welcome","pronunciation":"/də ʁjɛ̃/","sentence":"— Merci ! — De rien.","sentenceTranslation":"— Thanks! — You''re welcome.","keyPoints":["Literally ''of nothing''","Also: ''je vous en prie'' (formal)"]}'),
(1008, 'Greetings', 'comment allez-vous ?', 'how are you? (formal)', '["Formal — use with strangers, elders","Informal: ''comment vas-tu ?'' or ''ça va ?''"]', '{"id":1008,"category":"Greetings","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"comment allez-vous ?","back":"how are you? (formal)","pronunciation":"/kɔ.mɑ̃ ta.le vu/","sentence":"Bonjour Madame, comment allez-vous ?","sentenceTranslation":"Hello Ma''am, how are you?","keyPoints":["Formal — use with strangers, elders","Informal: ''comment vas-tu ?'' or ''ça va ?''"]}'),
(1009, 'Greetings', 'je m''appelle...', 'my name is...', '["Literally ''I call myself''","Reflexive verb: s''appeler"]', '{"id":1009,"category":"Greetings","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"je m''appelle...","back":"my name is...","pronunciation":"/ʒə ma.pɛl/","sentence":"Je m''appelle Marie, et vous ?","sentenceTranslation":"My name is Marie, and you?","keyPoints":["Literally ''I call myself''","Reflexive verb: s''appeler"]}'),
(1010, 'Greetings', 'oui / non', 'yes / no', '["''Si'' is used for ''yes'' when contradicting a negative"]', '{"id":1010,"category":"Greetings","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"oui / non","back":"yes / no","pronunciation":"/wi/ /nɔ̃/","sentence":"Oui, je comprends. Non, merci.","sentenceTranslation":"Yes, I understand. No, thank you.","keyPoints":["''Si'' is used for ''yes'' when contradicting a negative"]}'),
(1011, 'Greetings', 'How do you say ''please'' formally in French?', 's''il vous plaît', '[]', '{"id":1011,"category":"Greetings","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"fill-blank","front":"How do you say ''please'' formally in French?","back":"s''il vous plaît","correctAnswer":"s''il vous plaît","pronunciation":"/sil vu plɛ/","keyPoints":[]}'),
(1012, 'Greetings', 'What does ''au revoir'' literally mean?', '''Au revoir'' literally means ''until seeing again'' — it''s the standard formal goodbye.', '[]', '{"id":1012,"category":"Greetings","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"mcq","front":"What does ''au revoir'' literally mean?","back":"''Au revoir'' literally means ''until seeing again'' — it''s the standard formal goodbye.","choices":["Until tomorrow","Until seeing again","Good night","See you later"],"correctAnswer":1,"keyPoints":[]}'),
(1013, 'Greetings', 'Complete the greeting:', 'Bonjour, comment allez-vous ?', '[]', '{"id":1013,"category":"Greetings","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"cloze","front":"Complete the greeting:","back":"Bonjour, comment allez-vous ?","clozeText":"Bonjour, {{c1::comment}} allez-vous ?","correctAnswer":"comment","keyPoints":[]}'),
(1014, 'Greetings', 'bonne nuit', 'good night', '["Only used when going to bed","Not a greeting — only a farewell"]', '{"id":1014,"category":"Greetings","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"bonne nuit","back":"good night","pronunciation":"/bɔn nɥi/","sentence":"Bonne nuit, fais de beaux rêves.","sentenceTranslation":"Good night, sweet dreams.","keyPoints":["Only used when going to bed","Not a greeting — only a farewell"]}'),
(1015, 'Numbers', 'un, deux, trois, quatre, cinq', '1, 2, 3, 4, 5', '["Foundation numbers — memorize these first"]', '{"id":1015,"category":"Numbers","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"un, deux, trois, quatre, cinq","back":"1, 2, 3, 4, 5","pronunciation":"/œ̃, dø, tʁwa, katʁ, sɛ̃k/","sentence":"J''ai trois frères et deux sœurs.","sentenceTranslation":"I have three brothers and two sisters.","keyPoints":["Foundation numbers — memorize these first"]}'),
(1016, 'Numbers', 'six, sept, huit, neuf, dix', '6, 7, 8, 9, 10', '["Final consonants often silent unless followed by a vowel"]', '{"id":1016,"category":"Numbers","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"six, sept, huit, neuf, dix","back":"6, 7, 8, 9, 10","pronunciation":"/sis, sɛt, ɥit, nœf, dis/","sentence":"Il y a dix personnes dans la salle.","sentenceTranslation":"There are ten people in the room.","keyPoints":["Final consonants often silent unless followed by a vowel"]}'),
(1017, 'Numbers', 'vingt, trente, quarante, cinquante', '20, 30, 40, 50', '["Pattern: -ante ending for 30-60","70 = soixante-dix (60+10)"]', '{"id":1017,"category":"Numbers","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"vingt, trente, quarante, cinquante","back":"20, 30, 40, 50","pronunciation":"/vɛ̃, tʁɑ̃t, ka.ʁɑ̃t, sɛ̃.kɑ̃t/","sentence":"Elle a trente ans.","sentenceTranslation":"She is thirty years old.","keyPoints":["Pattern: -ante ending for 30-60","70 = soixante-dix (60+10)"]}'),
(1018, 'Numbers', 'soixante-dix, quatre-vingts, quatre-vingt-dix, cent', '70, 80, 90, 100', '["70 = 60+10, 80 = 4×20, 90 = 4×20+10","Belgian/Swiss French: septante, huitante/octante, nonante"]', '{"id":1018,"category":"Numbers","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"soixante-dix, quatre-vingts, quatre-vingt-dix, cent","back":"70, 80, 90, 100","pronunciation":"/swa.sɑ̃t dis, katʁ vɛ̃, katʁ vɛ̃ dis, sɑ̃/","sentence":"Mon grand-père a quatre-vingts ans.","sentenceTranslation":"My grandfather is eighty years old.","keyPoints":["70 = 60+10, 80 = 4×20, 90 = 4×20+10","Belgian/Swiss French: septante, huitante/octante, nonante"]}'),
(1019, 'Numbers', 'What is ''quatre-vingts'' in numbers?', 'Quatre-vingts = 80. Literally ''four twenties'' (4 × 20).', '[]', '{"id":1019,"category":"Numbers","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"mcq","front":"What is ''quatre-vingts'' in numbers?","back":"Quatre-vingts = 80. Literally ''four twenties'' (4 × 20).","choices":["40","60","80","90"],"correctAnswer":2,"keyPoints":[]}'),
(1020, 'Numbers', 'quelle heure est-il ?', 'what time is it?', '["Answer: ''il est deux heures'' (it is two o''clock)","24-hour clock common in France"]', '{"id":1020,"category":"Numbers","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"quelle heure est-il ?","back":"what time is it?","pronunciation":"/kɛ.l‿œʁ ɛ.t‿il/","sentence":"Excusez-moi, quelle heure est-il ?","sentenceTranslation":"Excuse me, what time is it?","keyPoints":["Answer: ''il est deux heures'' (it is two o''clock)","24-hour clock common in France"]}'),
(1021, 'Numbers', 'aujourd''hui / demain / hier', 'today / tomorrow / yesterday', '["aujourd''hui = au + jour + de + hui (on the day of today)"]', '{"id":1021,"category":"Numbers","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"aujourd''hui / demain / hier","back":"today / tomorrow / yesterday","pronunciation":"/o.ʒuʁ.dɥi/ /də.mɛ̃/ /jɛʁ/","sentence":"Aujourd''hui c''est lundi, demain c''est mardi.","sentenceTranslation":"Today is Monday, tomorrow is Tuesday.","keyPoints":["aujourd''hui = au + jour + de + hui (on the day of today)"]}'),
(1022, 'Numbers', 'lundi, mardi, mercredi, jeudi, vendredi, samedi, dimanche', 'Monday, Tuesday, Wednesday, Thursday, Friday, Saturday, Sunday', '["Days are NOT capitalized in French","Named after planets/gods like English"]', '{"id":1022,"category":"Numbers","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"lundi, mardi, mercredi, jeudi, vendredi, samedi, dimanche","back":"Monday, Tuesday, Wednesday, Thursday, Friday, Saturday, Sunday","pronunciation":"/lœ̃.di, maʁ.di, mɛʁ.kʁə.di, ʒø.di, vɑ̃.dʁə.di, sam.di, di.mɑ̃ʃ/","sentence":"Je travaille du lundi au vendredi.","sentenceTranslation":"I work from Monday to Friday.","keyPoints":["Days are NOT capitalized in French","Named after planets/gods like English"]}'),
(1023, 'Numbers', 'janvier, février, mars, avril, mai, juin', 'January, February, March, April, May, June', '["Months NOT capitalized in French","Use ''en'' for ''in'' with months"]', '{"id":1023,"category":"Numbers","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"janvier, février, mars, avril, mai, juin","back":"January, February, March, April, May, June","pronunciation":"/ʒɑ̃.vje, fe.vʁi.je, maʁs, a.vʁil, mɛ, ʒɥɛ̃/","sentence":"Mon anniversaire est en mars.","sentenceTranslation":"My birthday is in March.","keyPoints":["Months NOT capitalized in French","Use ''en'' for ''in'' with months"]}'),
(1024, 'Numbers', 'juillet, août, septembre, octobre, novembre, décembre', 'July, August, September, October, November, December', '["août — the ''a'' is silent","Similar to English (Latin roots)"]', '{"id":1024,"category":"Numbers","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"juillet, août, septembre, octobre, novembre, décembre","back":"July, August, September, October, November, December","pronunciation":"/ʒɥi.jɛ, ut, sɛp.tɑ̃bʁ, ɔk.tɔbʁ, nɔ.vɑ̃bʁ, de.sɑ̃bʁ/","sentence":"Noël est en décembre.","sentenceTranslation":"Christmas is in December.","keyPoints":["août — the ''a'' is silent","Similar to English (Latin roots)"]}'),
(1025, 'Numbers', 'How do you say ''today'' in French?', 'aujourd''hui', '[]', '{"id":1025,"category":"Numbers","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"fill-blank","front":"How do you say ''today'' in French?","back":"aujourd''hui","correctAnswer":"aujourd''hui","keyPoints":[]}'),
(1026, 'Food', 'le pain', 'bread', '["Masculine noun","Central to French cuisine — served at every meal"]', '{"id":1026,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le pain","back":"bread","pronunciation":"/lə pɛ̃/","sentence":"Je voudrais du pain, s''il vous plaît.","sentenceTranslation":"I would like some bread, please.","keyPoints":["Masculine noun","Central to French cuisine — served at every meal"]}'),
(1027, 'Food', 'le fromage', 'cheese', '["Masculine noun","France''s most iconic food category"]', '{"id":1027,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le fromage","back":"cheese","pronunciation":"/lə fʁɔ.maʒ/","sentence":"La France a plus de 400 types de fromage.","sentenceTranslation":"France has more than 400 types of cheese.","keyPoints":["Masculine noun","France''s most iconic food category"]}'),
(1028, 'Food', 'la viande', 'meat', '["Feminine noun","''je suis végétarien(ne)'' = I''m vegetarian"]', '{"id":1028,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"feminine","article":"la","front":"la viande","back":"meat","pronunciation":"/la vjɑ̃d/","sentence":"Je ne mange pas de viande.","sentenceTranslation":"I don''t eat meat.","keyPoints":["Feminine noun","''je suis végétarien(ne)'' = I''m vegetarian"]}'),
(1029, 'Food', 'le poisson', 'fish', '["Masculine noun","Don''t confuse with ''poison'' (poison)!"]', '{"id":1029,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le poisson","back":"fish","pronunciation":"/lə pwa.sɔ̃/","sentence":"Le poisson est frais aujourd''hui.","sentenceTranslation":"The fish is fresh today.","keyPoints":["Masculine noun","Don''t confuse with ''poison'' (poison)!"]}'),
(1030, 'Food', 'l''eau', 'water', '["Feminine noun (l'' before vowel)","Free tap water at restaurants: ''une carafe d''eau''"]', '{"id":1030,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"feminine","article":"l''","front":"l''eau","back":"water","pronunciation":"/lo/","sentence":"Une carafe d''eau, s''il vous plaît.","sentenceTranslation":"A carafe of water, please.","keyPoints":["Feminine noun (l'' before vowel)","Free tap water at restaurants: ''une carafe d''eau''"]}'),
(1031, 'Food', 'le café', 'coffee', '["Masculine noun","Also means ''café'' (the place)"]', '{"id":1031,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le café","back":"coffee","pronunciation":"/lə ka.fe/","sentence":"Un café noir, s''il vous plaît.","sentenceTranslation":"A black coffee, please.","keyPoints":["Masculine noun","Also means ''café'' (the place)"]}'),
(1032, 'Food', 'le vin', 'wine', '["Masculine noun","rouge = red, blanc = white, rosé = rosé"]', '{"id":1032,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le vin","back":"wine","pronunciation":"/lə vɛ̃/","sentence":"Un verre de vin rouge, s''il vous plaît.","sentenceTranslation":"A glass of red wine, please.","keyPoints":["Masculine noun","rouge = red, blanc = white, rosé = rosé"]}'),
(1033, 'Food', 'la salade', 'salad', '["Feminine noun","''prendre'' = to take/have (ordering food)"]', '{"id":1033,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"feminine","article":"la","front":"la salade","back":"salad","pronunciation":"/la sa.lad/","sentence":"Je prends une salade verte.","sentenceTranslation":"I''ll have a green salad.","keyPoints":["Feminine noun","''prendre'' = to take/have (ordering food)"]}'),
(1034, 'Food', 'je voudrais...', 'I would like...', '["Polite way to order — conditionnel of ''vouloir''","More polite than ''je veux'' (I want)"]', '{"id":1034,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"je voudrais...","back":"I would like...","pronunciation":"/ʒə vu.dʁɛ/","sentence":"Je voudrais un croissant et un café.","sentenceTranslation":"I would like a croissant and a coffee.","keyPoints":["Polite way to order — conditionnel of ''vouloir''","More polite than ''je veux'' (I want)"]}'),
(1035, 'Food', 'l''addition, s''il vous plaît', 'the check, please', '["Essential restaurant phrase","Tipping not expected in France (service included)"]', '{"id":1035,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"l''addition, s''il vous plaît","back":"the check, please","pronunciation":"/la.di.sjɔ̃ sil vu plɛ/","sentence":"On a fini. L''addition, s''il vous plaît.","sentenceTranslation":"We''re done. The check, please.","keyPoints":["Essential restaurant phrase","Tipping not expected in France (service included)"]}'),
(1036, 'Food', 'Which article goes with ''fromage''?', '''Le fromage'' — fromage is masculine. Always learn nouns with their article!', '[]', '{"id":1036,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"mcq","front":"Which article goes with ''fromage''?","back":"''Le fromage'' — fromage is masculine. Always learn nouns with their article!","choices":["la fromage","le fromage","l''fromage","les fromage"],"correctAnswer":1,"keyPoints":[]}'),
(1037, 'Food', 'Order a coffee politely:', 'Je voudrais un café, s''il vous plaît.', '[]', '{"id":1037,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"cloze","front":"Order a coffee politely:","back":"Je voudrais un café, s''il vous plaît.","clozeText":"Je {{c1::voudrais}} un café, s''il vous plaît.","correctAnswer":"voudrais","keyPoints":[]}'),
(1038, 'Food', 'le poulet', 'chicken', '["Masculine noun","poulet = chicken (meat), poule = hen"]', '{"id":1038,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le poulet","back":"chicken","pronunciation":"/lə pu.lɛ/","sentence":"Le poulet rôti est délicieux.","sentenceTranslation":"The roast chicken is delicious.","keyPoints":["Masculine noun","poulet = chicken (meat), poule = hen"]}'),
(1039, 'Food', 'la bière', 'beer', '["Feminine noun","pression = draft/draught"]', '{"id":1039,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"feminine","article":"la","front":"la bière","back":"beer","pronunciation":"/la bjɛʁ/","sentence":"Une bière pression, s''il vous plaît.","sentenceTranslation":"A draft beer, please.","keyPoints":["Feminine noun","pression = draft/draught"]}'),
(1040, 'Food', 'le dessert', 'dessert', '["Masculine noun","Same word as English, French pronunciation"]', '{"id":1040,"category":"Food","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le dessert","back":"dessert","pronunciation":"/lə de.sɛʁ/","sentence":"Qu''est-ce que vous avez comme dessert ?","sentenceTranslation":"What do you have for dessert?","keyPoints":["Masculine noun","Same word as English, French pronunciation"]}'),
(1041, 'Family', 'la famille', 'family', '["Feminine noun","Mon/ma/mes = my (possessives agree with noun gender)"]', '{"id":1041,"category":"Family","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"feminine","article":"la","front":"la famille","back":"family","pronunciation":"/la fa.mij/","sentence":"Ma famille habite à Paris.","sentenceTranslation":"My family lives in Paris.","keyPoints":["Feminine noun","Mon/ma/mes = my (possessives agree with noun gender)"]}'),
(1042, 'Family', 'le père / la mère', 'father / mother', '["père = masculine, mère = feminine","Also: papa/maman (dad/mom, informal)"]', '{"id":1042,"category":"Family","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le père / la mère","back":"father / mother","pronunciation":"/lə pɛʁ/ /la mɛʁ/","sentence":"Mon père est médecin, ma mère est professeur.","sentenceTranslation":"My father is a doctor, my mother is a teacher.","keyPoints":["père = masculine, mère = feminine","Also: papa/maman (dad/mom, informal)"]}'),
(1043, 'Family', 'le frère / la sœur', 'brother / sister', '["frère = masculine, sœur = feminine","œ is a unique French letter combination"]', '{"id":1043,"category":"Family","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le frère / la sœur","back":"brother / sister","pronunciation":"/lə fʁɛʁ/ /la sœʁ/","sentence":"J''ai un frère et deux sœurs.","sentenceTranslation":"I have one brother and two sisters.","keyPoints":["frère = masculine, sœur = feminine","œ is a unique French letter combination"]}'),
(1044, 'Family', 'le fils / la fille', 'son / daughter', '["fils: the ''l'' is silent","fille also means ''girl''"]', '{"id":1044,"category":"Family","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le fils / la fille","back":"son / daughter","pronunciation":"/lə fis/ /la fij/","sentence":"Leur fils a cinq ans.","sentenceTranslation":"Their son is five years old.","keyPoints":["fils: the ''l'' is silent","fille also means ''girl''"]}'),
(1045, 'Family', 'le mari / la femme', 'husband / wife', '["femme = both ''wife'' and ''woman''","mari = husband (not to be confused with Marie)"]', '{"id":1045,"category":"Family","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le mari / la femme","back":"husband / wife","pronunciation":"/lə ma.ʁi/ /la fam/","sentence":"Ma femme est française.","sentenceTranslation":"My wife is French.","keyPoints":["femme = both ''wife'' and ''woman''","mari = husband (not to be confused with Marie)"]}'),
(1046, 'Family', 'un ami / une amie', 'a friend (m/f)', '["Masculine: ami, feminine: amie","un copain/une copine = friend (informal) or boyfriend/girlfriend"]', '{"id":1046,"category":"Family","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"un","front":"un ami / une amie","back":"a friend (m/f)","pronunciation":"/œ̃.n‿a.mi/ /y.n‿a.mi/","sentence":"C''est mon meilleur ami.","sentenceTranslation":"He''s my best friend.","keyPoints":["Masculine: ami, feminine: amie","un copain/une copine = friend (informal) or boyfriend/girlfriend"]}'),
(1047, 'Family', 'un homme / une femme', 'a man / a woman', '["homme: the ''h'' is silent (liaison with article)","femme: same word for ''wife''"]', '{"id":1047,"category":"Family","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"un","front":"un homme / une femme","back":"a man / a woman","pronunciation":"/œ̃.n‿ɔm/ /yn fam/","sentence":"Cet homme est très grand.","sentenceTranslation":"That man is very tall.","keyPoints":["homme: the ''h'' is silent (liaison with article)","femme: same word for ''wife''"]}'),
(1048, 'Family', 'un garçon / une fille', 'a boy / a girl', '["garçon also means ''waiter'' (old-fashioned)","ç = ''s'' sound before a, o, u"]', '{"id":1048,"category":"Family","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"un","front":"un garçon / une fille","back":"a boy / a girl","pronunciation":"/œ̃ ɡaʁ.sɔ̃/ /yn fij/","sentence":"Le garçon joue dans le jardin.","sentenceTranslation":"The boy plays in the garden.","keyPoints":["garçon also means ''waiter'' (old-fashioned)","ç = ''s'' sound before a, o, u"]}'),
(1049, 'Family', 'How do you say ''my family'' in French? (ma ___)', 'ma famille', '[]', '{"id":1049,"category":"Family","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"fill-blank","front":"How do you say ''my family'' in French? (ma ___)","back":"ma famille","correctAnswer":"famille","keyPoints":[]}'),
(1050, 'Family', 'Complete: I have one brother and two sisters.', 'J''ai un frère et deux sœurs.', '[]', '{"id":1050,"category":"Family","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"cloze","front":"Complete: I have one brother and two sisters.","back":"J''ai un frère et deux sœurs.","clozeText":"J''ai un {{c1::frère}} et deux {{c2::sœurs}}.","correctAnswer":"frère","keyPoints":[]}'),
(1051, 'Directions', 'où est... ?', 'where is...?', '["Most useful navigation phrase","où = where (with accent)"]', '{"id":1051,"category":"Directions","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"où est... ?","back":"where is...?","pronunciation":"/u ɛ/","sentence":"Où est la gare, s''il vous plaît ?","sentenceTranslation":"Where is the train station, please?","keyPoints":["Most useful navigation phrase","où = where (with accent)"]}'),
(1052, 'Directions', 'à gauche / à droite / tout droit', 'left / right / straight ahead', '["tournez = turn (formal command)","gauche also means ''awkward''"]', '{"id":1052,"category":"Directions","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"à gauche / à droite / tout droit","back":"left / right / straight ahead","pronunciation":"/a ɡoʃ/ /a dʁwat/ /tu dʁwa/","sentence":"Tournez à gauche, puis tout droit.","sentenceTranslation":"Turn left, then straight ahead.","keyPoints":["tournez = turn (formal command)","gauche also means ''awkward''"]}'),
(1053, 'Directions', 'la gare', 'train station', '["Feminine noun","gare routière = bus station"]', '{"id":1053,"category":"Directions","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"feminine","article":"la","front":"la gare","back":"train station","pronunciation":"/la ɡaʁ/","sentence":"La gare est à cinq minutes d''ici.","sentenceTranslation":"The train station is five minutes from here.","keyPoints":["Feminine noun","gare routière = bus station"]}'),
(1054, 'Directions', 'le métro', 'subway / metro', '["Masculine noun","Paris metro has 16 lines"]', '{"id":1054,"category":"Directions","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le métro","back":"subway / metro","pronunciation":"/lə me.tʁo/","sentence":"Je prends le métro pour aller au travail.","sentenceTranslation":"I take the metro to go to work.","keyPoints":["Masculine noun","Paris metro has 16 lines"]}'),
(1055, 'Directions', 'la rue', 'street', '["Feminine noun","rue = street, avenue = avenue, boulevard = boulevard"]', '{"id":1055,"category":"Directions","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"feminine","article":"la","front":"la rue","back":"street","pronunciation":"/la ʁy/","sentence":"J''habite au 15 rue de la Paix.","sentenceTranslation":"I live at 15 rue de la Paix.","keyPoints":["Feminine noun","rue = street, avenue = avenue, boulevard = boulevard"]}'),
(1056, 'Directions', 'près de / loin de', 'near / far from', '["près de = near, loin de = far from","Always followed by ''de''"]', '{"id":1056,"category":"Directions","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"près de / loin de","back":"near / far from","pronunciation":"/pʁɛ də/ /lwɛ̃ də/","sentence":"L''hôtel est près de la gare.","sentenceTranslation":"The hotel is near the train station.","keyPoints":["près de = near, loin de = far from","Always followed by ''de''"]}');
INSERT INTO cards (id, category, front, back, key_points, data) VALUES
(1057, 'Directions', 'un billet', 'a ticket', '["Masculine noun","aller-retour = round trip, aller simple = one way"]', '{"id":1057,"category":"Directions","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"un","front":"un billet","back":"a ticket","pronunciation":"/œ̃ bi.jɛ/","sentence":"Un billet aller-retour pour Lyon, s''il vous plaît.","sentenceTranslation":"A round-trip ticket to Lyon, please.","keyPoints":["Masculine noun","aller-retour = round trip, aller simple = one way"]}'),
(1058, 'Directions', 'What does ''tout droit'' mean?', '''Tout droit'' means ''straight ahead''. It''s the direction to continue forward without turning.', '[]', '{"id":1058,"category":"Directions","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"mcq","front":"What does ''tout droit'' mean?","back":"''Tout droit'' means ''straight ahead''. It''s the direction to continue forward without turning.","choices":["Turn right","Turn left","Straight ahead","Go back"],"correctAnswer":2,"keyPoints":[]}'),
(1059, 'Verbs', 'être — je suis, tu es, il/elle est, nous sommes, vous êtes, ils/elles sont', 'to be — I am, you are, he/she is, we are, you are, they are', '["Most important French verb","Irregular — must memorize all forms","Used for identity, nationality, profession"]', '{"id":1059,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"être — je suis, tu es, il/elle est, nous sommes, vous êtes, ils/elles sont","back":"to be — I am, you are, he/she is, we are, you are, they are","pronunciation":"/ɛtʁ/","sentence":"Je suis français.","sentenceTranslation":"I am French.","keyPoints":["Most important French verb","Irregular — must memorize all forms","Used for identity, nationality, profession"]}'),
(1060, 'Verbs', 'avoir — j''ai, tu as, il/elle a, nous avons, vous avez, ils/elles ont', 'to have — I have, you have, he/she has, we have, you have, they have', '["Second most important verb","Used for age: ''j''ai X ans'' (I have X years)","Also used as auxiliary in passé composé"]', '{"id":1060,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"avoir — j''ai, tu as, il/elle a, nous avons, vous avez, ils/elles ont","back":"to have — I have, you have, he/she has, we have, you have, they have","pronunciation":"/a.vwaʁ/","sentence":"J''ai vingt-cinq ans.","sentenceTranslation":"I am twenty-five years old.","keyPoints":["Second most important verb","Used for age: ''j''ai X ans'' (I have X years)","Also used as auxiliary in passé composé"]}'),
(1061, 'Verbs', 'aller — je vais, tu vas, il/elle va, nous allons, vous allez, ils/elles vont', 'to go — I go, you go, he/she goes, we go, you go, they go', '["Irregular verb","Used for future: ''je vais + infinitive'' = I''m going to...","à + le = au, à + les = aux"]', '{"id":1061,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"aller — je vais, tu vas, il/elle va, nous allons, vous allez, ils/elles vont","back":"to go — I go, you go, he/she goes, we go, you go, they go","pronunciation":"/a.le/","sentence":"Je vais au supermarché.","sentenceTranslation":"I''m going to the supermarket.","keyPoints":["Irregular verb","Used for future: ''je vais + infinitive'' = I''m going to...","à + le = au, à + les = aux"]}'),
(1062, 'Verbs', 'faire — je fais, tu fais, il/elle fait, nous faisons, vous faites, ils/elles font', 'to do / to make', '["Used for weather: ''il fait beau'' (it''s nice out)","faire du sport = to exercise","faire les courses = to go shopping"]', '{"id":1062,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"faire — je fais, tu fais, il/elle fait, nous faisons, vous faites, ils/elles font","back":"to do / to make","pronunciation":"/fɛʁ/","sentence":"Qu''est-ce que tu fais ce soir ?","sentenceTranslation":"What are you doing tonight?","keyPoints":["Used for weather: ''il fait beau'' (it''s nice out)","faire du sport = to exercise","faire les courses = to go shopping"]}'),
(1063, 'Verbs', 'parler', 'to speak', '["Regular -er verb","je parle, tu parles, il parle, nous parlons, vous parlez, ils parlent","-er verbs = 90% of French verbs"]', '{"id":1063,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"parler","back":"to speak","pronunciation":"/paʁ.le/","sentence":"Je parle un peu français.","sentenceTranslation":"I speak a little French.","keyPoints":["Regular -er verb","je parle, tu parles, il parle, nous parlons, vous parlez, ils parlent","-er verbs = 90% of French verbs"]}'),
(1064, 'Verbs', 'manger', 'to eat', '["Regular -er verb (with spelling change: nous mangeons)","The ''e'' stays in ''nous mangeons'' to keep the soft ''g'' sound"]', '{"id":1064,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"manger","back":"to eat","pronunciation":"/mɑ̃.ʒe/","sentence":"Nous mangeons au restaurant ce soir.","sentenceTranslation":"We are eating at the restaurant tonight.","keyPoints":["Regular -er verb (with spelling change: nous mangeons)","The ''e'' stays in ''nous mangeons'' to keep the soft ''g'' sound"]}'),
(1065, 'Verbs', 'boire', 'to drink', '["Irregular: je bois, tu bois, il boit, nous buvons, vous buvez, ils boivent","Note the stem change: boi- → buv-"]', '{"id":1065,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"boire","back":"to drink","pronunciation":"/bwaʁ/","sentence":"Je bois de l''eau tous les jours.","sentenceTranslation":"I drink water every day.","keyPoints":["Irregular: je bois, tu bois, il boit, nous buvons, vous buvez, ils boivent","Note the stem change: boi- → buv-"]}'),
(1066, 'Verbs', 'comprendre', 'to understand', '["Essential survival phrase","Conjugated like ''prendre'' (to take)"]', '{"id":1066,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"comprendre","back":"to understand","pronunciation":"/kɔ̃.pʁɑ̃dʁ/","sentence":"Je ne comprends pas.","sentenceTranslation":"I don''t understand.","keyPoints":["Essential survival phrase","Conjugated like ''prendre'' (to take)"]}'),
(1067, 'Verbs', 'vouloir — je veux, tu veux, il veut, nous voulons, vous voulez, ils veulent', 'to want', '["Irregular verb","''je voudrais'' (I would like) is more polite than ''je veux''"]', '{"id":1067,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"vouloir — je veux, tu veux, il veut, nous voulons, vous voulez, ils veulent","back":"to want","pronunciation":"/vu.lwaʁ/","sentence":"Je veux apprendre le français.","sentenceTranslation":"I want to learn French.","keyPoints":["Irregular verb","''je voudrais'' (I would like) is more polite than ''je veux''"]}'),
(1068, 'Verbs', 'pouvoir — je peux, tu peux, il peut, nous pouvons, vous pouvez, ils peuvent', 'to be able to / can', '["Irregular verb","Used for permission and ability","''puis-je?'' = very formal ''may I?''"]', '{"id":1068,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"pouvoir — je peux, tu peux, il peut, nous pouvons, vous pouvez, ils peuvent","back":"to be able to / can","pronunciation":"/pu.vwaʁ/","sentence":"Est-ce que je peux avoir un verre d''eau ?","sentenceTranslation":"Can I have a glass of water?","keyPoints":["Irregular verb","Used for permission and ability","''puis-je?'' = very formal ''may I?''"]}'),
(1069, 'Verbs', 'habiter', 'to live (in a place)', '["Regular -er verb","habiter à = live in (city)","habiter en = live in (country)"]', '{"id":1069,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"habiter","back":"to live (in a place)","pronunciation":"/a.bi.te/","sentence":"J''habite à Paris depuis trois ans.","sentenceTranslation":"I''ve been living in Paris for three years.","keyPoints":["Regular -er verb","habiter à = live in (city)","habiter en = live in (country)"]}'),
(1070, 'Verbs', 'aimer', 'to like / to love', '["Regular -er verb","j''aime = I like/love","j''aime bien = I like (softer)","je t''aime = I love you"]', '{"id":1070,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"aimer","back":"to like / to love","pronunciation":"/e.me/","sentence":"J''aime le chocolat.","sentenceTranslation":"I like chocolate.","keyPoints":["Regular -er verb","j''aime = I like/love","j''aime bien = I like (softer)","je t''aime = I love you"]}'),
(1071, 'Verbs', 'travailler', 'to work', '["Regular -er verb","le travail = work (noun, masculine)"]', '{"id":1071,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"travailler","back":"to work","pronunciation":"/tʁa.va.je/","sentence":"Je travaille dans une banque.","sentenceTranslation":"I work in a bank.","keyPoints":["Regular -er verb","le travail = work (noun, masculine)"]}'),
(1072, 'Verbs', 'Complete: I am French.', 'Je suis français.', '[]', '{"id":1072,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"cloze","front":"Complete: I am French.","back":"Je suis français.","clozeText":"Je {{c1::suis}} français.","correctAnswer":"suis","keyPoints":[]}'),
(1073, 'Verbs', 'What is the correct form: ''Nous ___ au restaurant'' (aller)?', 'Nous allons au restaurant. ''Aller'' is irregular — each form must be memorized.', '[]', '{"id":1073,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"mcq","front":"What is the correct form: ''Nous ___ au restaurant'' (aller)?","back":"Nous allons au restaurant. ''Aller'' is irregular — each form must be memorized.","choices":["allons","allent","allez","alles"],"correctAnswer":0,"keyPoints":[]}'),
(1074, 'Verbs', 'How do you say ''I don''t understand'' in French?', 'Je ne comprends pas', '[]', '{"id":1074,"category":"Verbs","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"fill-blank","front":"How do you say ''I don''t understand'' in French?","back":"Je ne comprends pas","correctAnswer":"je ne comprends pas","keyPoints":[]}'),
(1075, 'Phrases', 'je ne comprends pas', 'I don''t understand', '["ne...pas = negation structure","Most important survival phrase"]', '{"id":1075,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"je ne comprends pas","back":"I don''t understand","pronunciation":"/ʒə nə kɔ̃.pʁɑ̃ pa/","sentence":"Désolé, je ne comprends pas. Pouvez-vous répéter ?","sentenceTranslation":"Sorry, I don''t understand. Can you repeat?","keyPoints":["ne...pas = negation structure","Most important survival phrase"]}'),
(1076, 'Phrases', 'parlez-vous anglais ?', 'do you speak English?', '["Useful fallback phrase","But try French first — locals appreciate the effort"]', '{"id":1076,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"parlez-vous anglais ?","back":"do you speak English?","pronunciation":"/paʁ.le vu ɑ̃.ɡlɛ/","sentence":"Excusez-moi, parlez-vous anglais ?","sentenceTranslation":"Excuse me, do you speak English?","keyPoints":["Useful fallback phrase","But try French first — locals appreciate the effort"]}'),
(1077, 'Phrases', 'je suis perdu(e)', 'I am lost', '["Add ''e'' if you''re female: perdue","First French adjective agreement rule"]', '{"id":1077,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"je suis perdu(e)","back":"I am lost","pronunciation":"/ʒə sɥi pɛʁ.dy/","sentence":"Excusez-moi, je suis perdu. Où est le métro ?","sentenceTranslation":"Excuse me, I''m lost. Where is the metro?","keyPoints":["Add ''e'' if you''re female: perdue","First French adjective agreement rule"]}'),
(1078, 'Phrases', 'combien ça coûte ?', 'how much does it cost?', '["Essential shopping phrase","combien = how much/many"]', '{"id":1078,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"combien ça coûte ?","back":"how much does it cost?","pronunciation":"/kɔ̃.bjɛ̃ sa kut/","sentence":"C''est joli ! Combien ça coûte ?","sentenceTranslation":"It''s pretty! How much does it cost?","keyPoints":["Essential shopping phrase","combien = how much/many"]}'),
(1079, 'Phrases', 'j''ai besoin de...', 'I need...', '["Literally ''I have need of''","besoin = need (noun)"]', '{"id":1079,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"j''ai besoin de...","back":"I need...","pronunciation":"/ʒe bə.zwɛ̃ də/","sentence":"J''ai besoin d''aide, s''il vous plaît.","sentenceTranslation":"I need help, please.","keyPoints":["Literally ''I have need of''","besoin = need (noun)"]}'),
(1080, 'Phrases', 'c''est / ce n''est pas', 'it is / it is not', '["c''est = it is (most common structure)","ce n''est pas = it is not"]', '{"id":1080,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"c''est / ce n''est pas","back":"it is / it is not","pronunciation":"/sɛ/ /sə nɛ pa/","sentence":"C''est très bon ! Ce n''est pas cher.","sentenceTranslation":"It''s very good! It''s not expensive.","keyPoints":["c''est = it is (most common structure)","ce n''est pas = it is not"]}'),
(1081, 'Phrases', 'il y a...', 'there is / there are...', '["Works for both singular and plural","il n''y a pas de... = there is no..."]', '{"id":1081,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"il y a...","back":"there is / there are...","pronunciation":"/il i a/","sentence":"Il y a un bon restaurant près d''ici.","sentenceTranslation":"There is a good restaurant near here.","keyPoints":["Works for both singular and plural","il n''y a pas de... = there is no..."]}'),
(1082, 'Phrases', 'je suis d''accord', 'I agree', '["d''accord = OK / agreed (very common)","pas d''accord = I disagree"]', '{"id":1082,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"je suis d''accord","back":"I agree","pronunciation":"/ʒə sɥi da.kɔʁ/","sentence":"Oui, je suis d''accord avec toi.","sentenceTranslation":"Yes, I agree with you.","keyPoints":["d''accord = OK / agreed (very common)","pas d''accord = I disagree"]}'),
(1083, 'Phrases', 'qu''est-ce que c''est ?', 'what is it? / what is this?', '["Long but very common question structure","Informal: ''c''est quoi ?'' (same meaning)"]', '{"id":1083,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"qu''est-ce que c''est ?","back":"what is it? / what is this?","pronunciation":"/kɛs kə sɛ/","sentence":"Qu''est-ce que c''est ? C''est un croissant.","sentenceTranslation":"What is this? It''s a croissant.","keyPoints":["Long but very common question structure","Informal: ''c''est quoi ?'' (same meaning)"]}'),
(1084, 'Phrases', 'je voudrais apprendre le français', 'I would like to learn French', '["Great practice sentence combining several structures","apprendre = to learn (irregular, like comprendre)"]', '{"id":1084,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"je voudrais apprendre le français","back":"I would like to learn French","pronunciation":"/ʒə vu.dʁɛ a.pʁɑ̃dʁ lə fʁɑ̃.sɛ/","sentence":"Je voudrais apprendre le français parce que j''aime la France.","sentenceTranslation":"I would like to learn French because I love France.","keyPoints":["Great practice sentence combining several structures","apprendre = to learn (irregular, like comprendre)"]}'),
(1085, 'Phrases', 'pouvez-vous répéter ?', 'can you repeat?', '["Essential when you don''t catch something","plus lentement = more slowly"]', '{"id":1085,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"pouvez-vous répéter ?","back":"can you repeat?","pronunciation":"/pu.ve vu ʁe.pe.te/","sentence":"Pardon, pouvez-vous répéter plus lentement ?","sentenceTranslation":"Sorry, can you repeat more slowly?","keyPoints":["Essential when you don''t catch something","plus lentement = more slowly"]}'),
(1086, 'Phrases', 'je ne sais pas', 'I don''t know', '["savoir = to know (facts)","connaître = to know (people, places)"]', '{"id":1086,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"je ne sais pas","back":"I don''t know","pronunciation":"/ʒə nə sɛ pa/","sentence":"Je ne sais pas où est la poste.","sentenceTranslation":"I don''t know where the post office is.","keyPoints":["savoir = to know (facts)","connaître = to know (people, places)"]}'),
(1087, 'Phrases', 'Complete: I don''t understand.', 'Je ne comprends pas.', '[]', '{"id":1087,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"cloze","front":"Complete: I don''t understand.","back":"Je ne comprends pas.","clozeText":"Je ne {{c1::comprends}} pas.","correctAnswer":"comprends","keyPoints":[]}'),
(1088, 'Phrases', 'What does ''il y a'' mean?', '''Il y a'' means ''there is'' or ''there are''. It works for both singular and plural.', '[]', '{"id":1088,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"mcq","front":"What does ''il y a'' mean?","back":"''Il y a'' means ''there is'' or ''there are''. It works for both singular and plural.","choices":["He has","There is/are","It is here","He goes"],"correctAnswer":1,"keyPoints":[]}'),
(1089, 'Phrases', 'd''accord', 'OK / agreed / alright', '["Most common agreement word","Used constantly in conversation"]', '{"id":1089,"category":"Phrases","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"d''accord","back":"OK / agreed / alright","pronunciation":"/da.kɔʁ/","sentence":"D''accord, on y va !","sentenceTranslation":"Alright, let''s go!","keyPoints":["Most common agreement word","Used constantly in conversation"]}'),
(1090, 'Adjectives', 'grand(e) / petit(e)', 'big, tall / small, short', '["Add ''e'' for feminine: grande, petite","Position: usually after noun, but grand/petit often before"]', '{"id":1090,"category":"Adjectives","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"grand(e) / petit(e)","back":"big, tall / small, short","pronunciation":"/ɡʁɑ̃/ /pə.ti/","sentence":"Paris est une grande ville.","sentenceTranslation":"Paris is a big city.","keyPoints":["Add ''e'' for feminine: grande, petite","Position: usually after noun, but grand/petit often before"]}'),
(1091, 'Adjectives', 'bon(ne) / mauvais(e)', 'good / bad', '["bon → bonne (f), bons/bonnes (pl)","bon goes BEFORE the noun (exception to normal rule)"]', '{"id":1091,"category":"Adjectives","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"bon(ne) / mauvais(e)","back":"good / bad","pronunciation":"/bɔ̃/ /mo.vɛ/","sentence":"C''est un bon restaurant.","sentenceTranslation":"It''s a good restaurant.","keyPoints":["bon → bonne (f), bons/bonnes (pl)","bon goes BEFORE the noun (exception to normal rule)"]}'),
(1092, 'Adjectives', 'beau (belle) / joli(e)', 'beautiful, handsome / pretty', '["beau → belle (f), bel (before vowel: un bel homme)","Goes BEFORE the noun"]', '{"id":1092,"category":"Adjectives","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"beau (belle) / joli(e)","back":"beautiful, handsome / pretty","pronunciation":"/bo/ /ʒɔ.li/","sentence":"C''est une belle journée.","sentenceTranslation":"It''s a beautiful day.","keyPoints":["beau → belle (f), bel (before vowel: un bel homme)","Goes BEFORE the noun"]}'),
(1093, 'Adjectives', 'chaud(e) / froid(e)', 'hot / cold', '["Used for weather: ''il fait chaud/froid''","For food: ''c''est chaud'' (it''s hot)"]', '{"id":1093,"category":"Adjectives","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"chaud(e) / froid(e)","back":"hot / cold","pronunciation":"/ʃo/ /fʁwa/","sentence":"Il fait chaud aujourd''hui.","sentenceTranslation":"It''s hot today.","keyPoints":["Used for weather: ''il fait chaud/froid''","For food: ''c''est chaud'' (it''s hot)"]}'),
(1094, 'Adjectives', 'nouveau (nouvelle) / vieux (vieille)', 'new / old', '["Irregular: nouveau → nouvel (before vowel), nouvelle (f)","vieux → vieil (before vowel), vieille (f)"]', '{"id":1094,"category":"Adjectives","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"nouveau (nouvelle) / vieux (vieille)","back":"new / old","pronunciation":"/nu.vo/ /vjø/","sentence":"J''ai un nouveau téléphone.","sentenceTranslation":"I have a new phone.","keyPoints":["Irregular: nouveau → nouvel (before vowel), nouvelle (f)","vieux → vieil (before vowel), vieille (f)"]}'),
(1095, 'Adjectives', 'facile / difficile', 'easy / difficult', '["Same form for masculine and feminine","Most adjectives ending in -e don''t change"]', '{"id":1095,"category":"Adjectives","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"facile / difficile","back":"easy / difficult","pronunciation":"/fa.sil/ /di.fi.sil/","sentence":"Le français n''est pas facile, mais c''est intéressant.","sentenceTranslation":"French isn''t easy, but it''s interesting.","keyPoints":["Same form for masculine and feminine","Most adjectives ending in -e don''t change"]}'),
(1096, 'Adjectives', 'content(e) / triste', 'happy / sad', '["content = happy (about something)","heureux/heureuse = happy (general state)"]', '{"id":1096,"category":"Adjectives","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"content(e) / triste","back":"happy / sad","pronunciation":"/kɔ̃.tɑ̃/ /tʁist/","sentence":"Je suis très content de vous rencontrer.","sentenceTranslation":"I am very happy to meet you.","keyPoints":["content = happy (about something)","heureux/heureuse = happy (general state)"]}'),
(1097, 'Adjectives', 'cher (chère) / gratuit(e)', 'expensive / free', '["cher also means ''dear'' (mon cher ami)","gratuit = free of charge"]', '{"id":1097,"category":"Adjectives","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","front":"cher (chère) / gratuit(e)","back":"expensive / free","pronunciation":"/ʃɛʁ/ /ɡʁa.tɥi/","sentence":"Ce n''est pas cher. L''entrée est gratuite.","sentenceTranslation":"It''s not expensive. Entry is free.","keyPoints":["cher also means ''dear'' (mon cher ami)","gratuit = free of charge"]}'),
(1098, 'Adjectives', 'Complete: It''s a beautiful day.', 'C''est une belle journée.', '[]', '{"id":1098,"category":"Adjectives","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","exerciseType":"cloze","front":"Complete: It''s a beautiful day.","back":"C''est une belle journée.","clozeText":"C''est une {{c1::belle}} journée.","correctAnswer":"belle","keyPoints":[]}'),
(1099, 'Places', 'la maison', 'house / home', '["Feminine noun","à la maison = at home / going home"]', '{"id":1099,"category":"Places","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"feminine","article":"la","front":"la maison","back":"house / home","pronunciation":"/la mɛ.zɔ̃/","sentence":"Je rentre à la maison.","sentenceTranslation":"I''m going home.","keyPoints":["Feminine noun","à la maison = at home / going home"]}'),
(1100, 'Places', 'le restaurant', 'restaurant', '["Masculine noun","au restaurant = à + le restaurant"]', '{"id":1100,"category":"Places","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le restaurant","back":"restaurant","pronunciation":"/lə ʁɛs.to.ʁɑ̃/","sentence":"On mange au restaurant ce soir ?","sentenceTranslation":"Shall we eat at the restaurant tonight?","keyPoints":["Masculine noun","au restaurant = à + le restaurant"]}'),
(1101, 'Places', 'le supermarché', 'supermarket', '["Masculine noun","Also: l''épicerie = small grocery store"]', '{"id":1101,"category":"Places","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le supermarché","back":"supermarket","pronunciation":"/lə sy.pɛʁ.maʁ.ʃe/","sentence":"Je vais au supermarché acheter du lait.","sentenceTranslation":"I''m going to the supermarket to buy milk.","keyPoints":["Masculine noun","Also: l''épicerie = small grocery store"]}'),
(1102, 'Places', 'la pharmacie', 'pharmacy', '["Feminine noun","Green cross sign — easy to spot in France"]', '{"id":1102,"category":"Places","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"feminine","article":"la","front":"la pharmacie","back":"pharmacy","pronunciation":"/la faʁ.ma.si/","sentence":"La pharmacie est ouverte jusqu''à 20 heures.","sentenceTranslation":"The pharmacy is open until 8 PM.","keyPoints":["Feminine noun","Green cross sign — easy to spot in France"]}'),
(1103, 'Places', 'l''hôpital', 'hospital', '["Masculine noun (l'' before vowel/h)","urgences = emergency room"]', '{"id":1103,"category":"Places","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"l''","front":"l''hôpital","back":"hospital","pronunciation":"/lo.pi.tal/","sentence":"L''hôpital est à dix minutes en voiture.","sentenceTranslation":"The hospital is ten minutes by car.","keyPoints":["Masculine noun (l'' before vowel/h)","urgences = emergency room"]}'),
(1104, 'Places', 'la boulangerie', 'bakery', '["Feminine noun","Iconic French shop — fresh baguettes daily"]', '{"id":1104,"category":"Places","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"feminine","article":"la","front":"la boulangerie","back":"bakery","pronunciation":"/la bu.lɑ̃ʒ.ʁi/","sentence":"J''achète du pain à la boulangerie chaque matin.","sentenceTranslation":"I buy bread at the bakery every morning.","keyPoints":["Feminine noun","Iconic French shop — fresh baguettes daily"]}'),
(1105, 'Places', 'le travail', 'work / job', '["Masculine noun","aller au travail = go to work"]', '{"id":1105,"category":"Places","type":"vocabulary","deck":"french-a1","cefrLevel":"A1","gender":"masculine","article":"le","front":"le travail","back":"work / job","pronunciation":"/lə tʁa.vaj/","sentence":"Je vais au travail en métro.","sentenceTranslation":"I go to work by metro.","keyPoints":["Masculine noun","aller au travail = go to work"]}'),
